INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Compliance Manager', 'CTL-056', '["Conduct regular risk assessments to align with APRA requirements and the ASD Essential Eight.","Engage with stakeholders throughout the process to ensure comprehensive understanding and support.","Document every stage of the engagement acceptance process thoroughly for transparent record-keeping.","Regularly train staff on regulatory requirements and compliance protocols to maintain a culture of compliance."]', NULL, 'Documented control objectives suitable for assurance engagement; management''s assertion prepared in accordance with criteria.', NULL, 'hybrid', 'Engagement Acceptance and Continuance (ASAE 3150)', 'critical', 'Engagement letter, control objectives schedule, management assertion', 'To effectively implement control CTL-056 under ASAE 3150 for Engagement Acceptance and Continuance, organizations in Australia must ensure they establish documented control objectives and management assertions that align with defined criteria. This involves a collaborative process that involves both automated tools and manual procedures, ensuring that engagement objectives reflect the broader regulatory landscape including the Australian Privacy Principles (APPs) and APRA standards. Furthermore, leveraging automated tools can streamline documentation and tracking while manual review processes will ensure compliance and thorough understanding of the risks involved in maintaining assurance engagements.
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO / Compliance', 'CTL-057', '["Ensure ongoing training and awareness for staff related to ASAE 3150 and compliance workflows.","Utilize a centralized repository for control documentation that is regularly updated.","Adopt a risk-based approach to assessing the effectiveness of controls.","Engage with assurance practitioners early in the control documentation process."]', NULL, 'System description fairly presents the controls implemented; description aligns with assurance practitioner expectations.', NULL, 'hybrid', 'Description of Controls Suitability (ASAE 3150)', 'critical', 'System description document, control matrix, walkthroughs', 'To implement the control CTL-057 under ASAE 3150 effectively, organizations in Australia must ensure that the description of internal controls is transparent, accurate, and meets the expectations set by assurance practitioners. This process involves meticulously documenting how controls are operationalized and ensuring alignment with relevant regulatory requirements, such as the Australian Privacy Principles and APRA guidelines. Organizations need a combination of manual documentation practices and automated tools to generate and maintain this control description to achieve a reliable and up-to-date system representation. This ensures that they comply with local laws while remaining clear on risk management tactics to support ongoing assurance engagements.
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Internal Audit / Compliance', 'CTL-058', '["Conduct regular training sessions for staff on ASAE 3150 requirements and compliance duties.","Utilize a continuous improvement approach for control testing based on AUDIT findings.","Maintain detailed documentation and evidence for each testing cycle to ensure readiness for external audits."]', NULL, 'Controls operate effectively over the period under review; sufficient appropriate evidence available for testing.', NULL, 'hybrid', 'Operating Effectiveness Testing (ASAE 3150 Type 2)', 'critical', 'Sample evidence per control, testing workpapers, exception register', 'To effectively implement Control CTL-058 under ASAE 3150, organizations in Australia must establish a robust framework that assures the ongoing effectiveness of controls over the review period. Given the complexities of the Australian regulatory environment, including compliance with the Australian Privacy Principles (APPs), APRA requirements, and the Security of Critical Infrastructure (SOCI) Act, it is vital for organizations to leverage both manual and automated approaches. This hybrid model allows for comprehensive coverage, ensuring that control measures are not only in place but are also functioning as intended.
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Vendor Manager / Compliance', 'CTL-059', '["Conduct thorough due diligence on all subservice organisations to ensure they meet ASAE 3150 requirements.","Regularly review and update risk assessment procedures to remain aligned with current Australian standards and regulations.","Establish clear communication channels with subservice entities for ongoing compliance and monitoring.","Incorporate privacy impact assessments as part of the evaluation to protect personal data as mandated by the APRA."]', NULL, 'Sub-service organisations identified; carve-out or inclusive method documented with complementary user/sub-service controls.', NULL, 'hybrid', 'Subservice Organisation Carve-out / Inclusive Method (ASAE 3150)', 'high', 'Subservice list, CUEC table, inclusive sub-service evidence', 'Implementing the Control ID CTL-059 under the ASAE 3150 framework necessitates a thorough understanding of how subservice organisations affect the service delivery and the associated controls. In Australian context, this requires compliance with the Australian Privacy Principles, APRA requirements, and the SOCI Act. The control can be approached either via a carve-out method, which excludes certain subservice organisation controls from the scope, or through the inclusive method, where all controls are accounted for in the engagement report. Documentation of complementary user and subservice controls is critical to ensure comprehensive oversight and alignment with regulatory bodies such as the Australian Signals Directorate (ASD) through the Essential Eight framework, which emphasizes the protection of data and systems from cyber threats.', '["Failing to adequately assess and document all relevant complementary user controls leading to compliance gaps.","Neglecting to maintain updated records of the services provided by subservice organisations, resulting in outdated risk evaluations.","Overcomplicating the carve-out process, which may confuse stakeholders and hinder effective implementation."]', 'quarterly', 'ASAE3150', 'For the hybrid approach, manual procedures might include quarterly reviews of the compliance documentation, direct communications with subservice organisations to collect performance metrics, and evidence of their compliance with key controls. Each of these processes should align with Australian Privacy Principles, ensuring that data handling is appropriate and risk is minimized.', 'Automated solutions like AWS IAM for identity management and Okta for access control can facilitate the oversight of subservice organisation interactions. Additionally, SIEM tools like Splunk can help in logging activities and detecting anomalies, ensuring compliance and security monitoring.', 'To test and validate this control, conduct regular internal audits and assessments against the ASAE 3150 criteria. Use penetration testing on the interfaces between primary entities and subservice providers. Additionally, seek external compliance verification through independent third-party assessments.', 'Subservice Organisations', 'not_started', '[{"description":"Conduct a detailed assessment of all third-party organisations involved in the delivery of services. This should include identifying the services provided, the risks associated with these services, and their significance to your overall compliance posture.","step_number":1,"title":"Identify Subservice Organisations","responsible_role":"Compliance Manager"},{"description":"Evaluate if the services of identified subservice organizations should be treated under a carve-out or inclusive method. For carve-out, outline which controls are excluded and rationale; for inclusive, ensure all controls are documented and assessed.","step_number":2,"title":"Determine Method: Carve-out or Inclusive","responsible_role":"Risk Officer"},{"description":"Document the user entity''s complementary controls that exist to govern subservice organisation operations. Ensure that these are validated against ASAE 3150 and reflect the requirements set forth by APRA and other relevant Australian authorities.","step_number":3,"title":"Document Complementary Controls","responsible_role":"Internal Auditor"},{"description":"Perform a thorough risk assessment on the identified subservice organisations based on the method you have chosen (carve-out or inclusive). Apply relevant criteria such as impact assessments and compliance with Australian standards.","step_number":4,"title":"Conduct Risk Assessment","responsible_role":"Risk Management team"},{"description":"Based on the risk assessment, implement necessary controls to address any identified gaps. This should also include aligning with the ASD Essential Eight to enhance cybersecurity resilience.","step_number":5,"title":"Implementation of Controls","responsible_role":"IT Security Manager"},{"description":"Establish monitoring mechanisms to ensure that the implemented controls are working effectively. This includes ongoing reporting on subservice performance and compliance with the carved-out or inclusive controls.","step_number":6,"title":"Monitoring and Reporting","responsible_role":"Compliance Officer"}]', '["AWS IAM","Okta","Splunk","ServiceNow","Microsoft Azure AD"]', '69f96fda5eaf8b697748c227', '2026-05-05T04:19:38.942000', '2026-05-05T05:03:52.047000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "control_id" = EXCLUDED."control_id", "best_practices" = EXCLUDED."best_practices", "target_date" = EXCLUDED."target_date", "description" = EXCLUDED."description", "implementation_notes" = EXCLUDED."implementation_notes", "implementation_type" = EXCLUDED."implementation_type", "title" = EXCLUDED."title", "priority" = EXCLUDED."priority", "evidence_required" = EXCLUDED."evidence_required", "implementation_overview" = EXCLUDED."implementation_overview", "common_pitfalls" = EXCLUDED."common_pitfalls", "frequency" = EXCLUDED."frequency", "framework" = EXCLUDED."framework", "manual_procedures" = EXCLUDED."manual_procedures", "automation_details" = EXCLUDED."automation_details", "testing_and_validation" = EXCLUDED."testing_and_validation", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "implementation_steps" = EXCLUDED."implementation_steps", "tools_and_systems" = EXCLUDED."tools_and_systems", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Compliance Manager', 'CTL-060', '["Align CUECs with ASAE 3150 and relevant Australian Standards","Regularly train staff on CUECs and their importance","Incorporate user feedback into control updates","Utilize technology for monitoring and reporting compliance with CUECs"]', NULL, 'Document and communicate complementary user entity controls required for the system to achieve its control objectives.', NULL, 'hybrid', 'Complementary User Entity Controls (CUECs) (ASAE 3150)', 'high', 'CUEC schedule, customer notifications', 'Implementing complementary user entity controls (CUECs) within the ASAE 3150 framework is crucial for ensuring that the security measures in place at subservice organizations are effectively complemented by user actions. In the Australian context, organizations must align these controls with the Australian Privacy Principles (APPs) as well as APRA requirements, ensuring that personal data is safeguarded while facilitating compliance with the SOCI Act and adhering to the ASD Essential Eight guidelines. 
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CTL-061', '["Implement multi-factor authentication for all access to CDR data in line with best practices.","Regularly update and patch systems to mitigate vulnerabilities, adhering to the ASD Essential Eight framework.","Conduct thorough vendor risk assessments for third-party service providers handling CDR data."]', NULL, 'Maintain governance, policies, processes, controls and capabilities for managing information security risks across the CDR data environment.', NULL, 'hybrid', 'CDR Information Security Capability (CDR Schedule 2 Part 1)', 'critical', 'CDR ISMS, security capability statement, governance records', 'Implementing the CDR Information Security Capability requires a comprehensive approach that integrates both manual and automated processes to ensure the secure management of CDR data. This setup must address Australian-specific regulatory requirements under the Consumer Data Right (CDR), aligning with the Australian Privacy Principles (APPs) and standards such as ISO 27001. Organizations should start by establishing a governance framework that defines roles and responsibilities for managing information security within the CDR data environment.', '["Neglecting regular updates and reviews of information security policies.","Inadequate training leading to employee unawareness of security practices.","Failure to comply with the specific timelines and requirements set forth in the SOCI Act for incident reporting."]', 'quarterly', 'CDR', 'In addition to automated controls, develop manual procedures for complex processes such as risk assessment and incident response, ensuring detailed documentation of each step to facilitate compliance and audit requirements. Engage stakeholders in review processes to ensure comprehensive coverage.', 'Leverage automation tools such as Security Information and Event Management (SIEM) systems (e.g., Splunk, Sumo Logic) for real-time monitoring and reporting of information security events. Automate compliance checks using tools that can validate adherence to APRA requirements and CDR obligations.', 'Validate this control by conducting penetration tests and simulated security breaches to assess response and resilience capabilities. Additionally, review the implementation of automated monitoring tools to ensure they generate accurate alerts and compliance reports.', 'CDR Information Security', 'not_started', '[{"description":"Define a governance structure that incorporates roles such as a Data Protection Officer (DPO) and Information Security Officer (ISO) to oversee information security tasks. This framework should also include policies aligning with APPs and other relevant Australian regulations.","step_number":1,"title":"Establish Governance Framework","responsible_role":"Compliance Officer"},{"description":"Create detailed information security policies covering data classification, access controls, incident response, and risk management. Policies should be developed in line with the Australian Prudential Regulation Authority (APRA) requirements and the Security of Critical Infrastructure (SOCI) Act.","step_number":2,"title":"Develop Information Security Policies","responsible_role":"Information Security Officer"},{"description":"Conduct a risk assessment to identify vulnerabilities associated with CDR data processing. Develop a risk management plan that includes mitigation strategies while ensuring compliance with ASD Essential Eight guidelines. Regularly review and update this plan to address new risks.","step_number":3,"title":"Implement Risk Management Processes","responsible_role":"Risk Manager"},{"description":"Implement technical controls such as firewalls, intrusion detection systems (IDS), and encryption tools to protect CDR data. Utilize automated monitoring solutions to ensure compliance with the implemented policies.","step_number":4,"title":"Deploy Technical Controls","responsible_role":"IT Security Team"},{"description":"Develop and roll out a training program for employees on information security best practices, focusing on their roles in protecting CDR data. Include specific training on APRA requirements and the consequences of breaches.","step_number":5,"title":"Conduct Training and Awareness Programs","responsible_role":"HR and Compliance Officer"},{"description":"Create procedures for reporting and responding to security incidents involving CDR data. Ensure processes align with the requirements of the SOCI Act and provide for timely notification to relevant authorities and affected individuals.","step_number":6,"title":"Establish Incident Management Procedures","responsible_role":"Incident Response Team"},{"description":"Plan and conduct regular audits of security controls and policies to ensure compliance with CDR and Australian legislative requirements. Use both internal and external auditors for an unbiased review.","step_number":7,"title":"Regular Audits and Reviews","responsible_role":"Internal Auditor"}]', '["Splunk for security monitoring and compliance reporting","Okta for identity and access management","AWS IAM for managing access to CDR data","Tenable for vulnerability management"]', '69f96fda5eaf8b697748c229', '2026-05-05T04:19:38.942000', '2026-05-05T05:03:52.476000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "control_id" = EXCLUDED."control_id", "best_practices" = EXCLUDED."best_practices", "target_date" = EXCLUDED."target_date", "description" = EXCLUDED."description", "implementation_notes" = EXCLUDED."implementation_notes", "implementation_type" = EXCLUDED."implementation_type", "title" = EXCLUDED."title", "priority" = EXCLUDED."priority", "evidence_required" = EXCLUDED."evidence_required", "implementation_overview" = EXCLUDED."implementation_overview", "common_pitfalls" = EXCLUDED."common_pitfalls", "frequency" = EXCLUDED."frequency", "framework" = EXCLUDED."framework", "manual_procedures" = EXCLUDED."manual_procedures", "automation_details" = EXCLUDED."automation_details", "testing_and_validation" = EXCLUDED."testing_and_validation", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "implementation_steps" = EXCLUDED."implementation_steps", "tools_and_systems" = EXCLUDED."tools_and_systems", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO / Architecture', 'CTL-062', '["Regularly perform risk assessments aligned with APRA guidelines to assess vulnerabilities associated with CDR data environments.","Ensure vendor agreements comply with CDR requirements, including data security standards derived from the APP and SOCI Act.","Implement the ASD Essential Eight framework to enhance the security posture of systems that handle CDR data."]', NULL, 'Clearly define and document the boundary of the CDR data environment, including systems, networks, personnel, vendors that interact with CDR data.', NULL, 'manual', 'CDR Data Environment Boundary Definition (CDR Schedule 2)', 'critical', 'Boundary diagram, scoping document, system inventory (CDR-tagged)', 'Implementing the CDR Data Environment Boundary Definition control (CTL-062) requires organizations to systematically demarcate the boundaries of their CDR data environments, ensuring that all involved systems, networks, personnel, and vendors are clearly identified and documented. In Australia, this is crucial not just for compliance with the Consumer Data Right (CDR) framework, but also for alignment with the Australian Privacy Principles (APPs), which emphasize the responsibility of organizations to manage personal information securely. Additionally, compliance with the Australian Prudential Regulation Authority (APRA) requirements and the Security of Critical Infrastructure (SOCI) Act necessitates thorough delineation to protect sensitive consumer data from unauthorized access or breaches. 
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('IT Security', 'CTL-063', '["Adopt the ASD Essential Eight strategies for enhanced cybersecurity resilience.","Regularly update access controls based on changes in personnel roles or project requirements.","Ensure all access requests and approvals are logged and retain these logs for auditing purposes."]', NULL, 'Strong authentication (MFA), least-privilege access controls, privileged access management for personnel accessing CDR data.', NULL, 'hybrid', 'CDR Access Controls and Authentication (CDR Schedule 2 Part 1 Step 4)', 'critical', 'MFA enforcement, PAM logs, JML records for CDR access', 'Implementing CDR Access Controls and Authentication (CTL-063) in Australia is essential for ensuring the security of consumer data under the Consumer Data Right (CDR) legislation. Organizations must establish strong authentication mechanisms, such as Multi-Factor Authentication (MFA), and employ least-privilege access controls to protect consumer data from unauthorized access. This control aligns with the Australian Privacy Principles (APPs) as well as the Australian Signals Directorate''s (ASD) Essential Eight strategies to mitigate cybersecurity risks. The integration of both manual and automated processes allows organizations to tailor their approach according to their specific operational and risk environments, thereby ensuring compliance with both regulatory requirements and industry best practices.
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Security Architecture', 'CTL-064', '["Regularly update and patch systems to support current encryption standards","Conduct regular training for employees regarding data protection best practices","Implement multi-factor authentication for systems handling encryption keys","Engage in regular risk assessments and penetration testing to identify vulnerabilities","Stay updated with CDR and APP regulatory developments to adjust practices accordingly"]', NULL, 'CDR data must be encrypted in transit (TLS 1.2+) and at rest (AES-256 or equivalent); key management aligned to ACCC/OAIC expectations.', NULL, 'hybrid', 'CDR Data Encryption in Transit and At Rest (CDR Schedule 2)', 'critical', 'TLS configs, KMS records, encryption attestations', 'Implementing the CDR Data Encryption Control (CTL-064) entails ensuring that Consumer Data Right (CDR) data is securely encrypted both in transit and at rest, in line with the ACCC and OAIC guidelines. For Australian organisations handling CDR data, compliance is paramount not only for customer trust but also for adherence to the Australian Privacy Principles (APPs) and the APRA requirements. This control mandates the use of TLS 1.2 or higher for data in transit, ensuring that any data exchanged over networks is safeguarded against interception and unauthorized access.
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('DPO / Privacy Officer', 'CTL-065', '["Conduct routine training for staff on privacy obligations under the Privacy Act 1988 and CDR guidelines.","Integrate PIAs into all project management processes as standard practice for projects involving personal data.","Maintain an up-to-date register of PIAs conducted and their outcomes for governance and compliance tracking."]', NULL, 'Conduct PIA prior to commencing or materially changing CDR data handling; address compliance with Privacy Safeguards.', NULL, 'manual', 'CDR Privacy Impact Assessment (Privacy Safeguard 1)', 'high', 'PIA reports, sign-off, remediation actions', 'To implement Control ID CTL-065 effectively in the Australian context, organizations must conduct a thorough Privacy Impact Assessment (PIA) whenever they initiate or significantly alter their handling of Consumer Data Right (CDR) data. This ensures compliance with Australian Privacy Principle (APP) 1 and aligns with the requirements set forth by the Office of the Australian Information Commissioner (OAIC). Organizations need to establish governance frameworks that embed PIA processes into their project planning methodologies. This should involve collaboration between legal, compliance, and IT teams to address potential privacy risks and ensure that data handling practices conform to the latest regulatory standards, including the Privacy Act and the Consumer Data Right legislation. 
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('DPO / Product', 'CTL-066', '["Design the consent dashboard for clarity and user-friendliness according to UX principles to enhance consumer engagement.","Ensure that records of consent are timestamped and securely stored to comply with APRA requirements.","Implement regular audits and assessments of consent practices to align with ISO27001 standards.","Provide transparency about how consent is used and the implications of withdrawal, adhering to the Australian Privacy Principles."]', NULL, 'Express, voluntary, time-limited, specific consent obtained from CDR consumers; consent dashboard with withdrawal mechanism within standards.', NULL, 'hybrid', 'CDR Consumer Consent Management (Privacy Safeguard 3, CDR Rules)', 'critical', 'Consent records, dashboard screenshots, withdrawal logs', 'Implementing CDR Consumer Consent Management is crucial for compliance with Privacy Safeguard 3 under the Consumer Data Right (CDR) framework in Australia. Organizations need to ensure they obtain express, voluntary, time-limited, and specific consent from consumers for the collection, use, and disclosure of their data. A well-designed consent management system must provide a user-friendly consent dashboard that enables consumers to view and withdraw their consent easily. Given the sensitive nature of personal information, it is essential to align the implementation with Australian Privacy Principles (APPs) and the Australian Government’s data protection standards, ensuring that all data handling practices uphold consumer rights and privacy protections.
INSERT INTO "control" ("owner", "control_id", "best_practices", "target_date", "description", "implementation_notes", "implementation_type", "title", "priority", "evidence_required", "implementation_overview", "common_pitfalls", "frequency", "framework", "manual_procedures", "automation_details", "testing_and_validation", "category", "status", "implementation_steps", "tools_and_systems", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Product / DPO', 'CTL-067', '[]', NULL, 'Notify CDR consumer when CDR data is disclosed in accordance with PS10; maintain CDR receipts.', NULL, 'automated', 'CDR Notification of Disclosure (Privacy Safeguard 10)', 'high', 'Notification logs, CDR receipts', NULL, '[]', 'Per disclosure', 'CDR', NULL, NULL, NULL, 'CDR Privacy', 'not_started', '[]', '[]', '69f96fda5eaf8b697748c22f', '2026-05-05T04:19:38.942000', '2026-05-05T05:03:53.987000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "control_id" = EXCLUDED."control_id", "best_practices" = EXCLUDED."best_practices", "target_date" = EXCLUDED."target_date", "description" = EXCLUDED."description", "implementation_notes" = EXCLUDED."implementation_notes", "implementation_type" = EXCLUDED."implementation_type", "title" = EXCLUDED."title", "priority" = EXCLUDED."priority", "evidence_required" = EXCLUDED."evidence_required", "implementation_overview" = EXCLUDED."implementation_overview", "common_pitfalls" = EXCLUDED."common_pitfalls", "frequency" = EXCLUDED."frequency", "framework" = EXCLUDED."framework", "manual_procedures" = EXCLUDED."manual_procedures", "automation_details" = EXCLUDED."automation_details", "testing_and_validation" = EXCLUDED."testing_and_validation", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "implementation_steps" = EXCLUDED."implementation_steps", "tools_and_systems" = EXCLUDED."tools_and_systems", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
