INSERT INTO "risk" ("owner", "treatment", "risk_id", "likelihood", "risk_score", "frameworks", "treatment_plan", "impact", "description", "title", "category", "status", "linked_control_ids", "linked_obligation_ids", "linked_task_ids", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Cloud Security Lead', 'mitigate', 'RSK-011', 3, 12, '["ISO27017"]', 'Implement responsibility matrix via CTL-001 and enforce responsibility reviews', 4, 'Ambiguity between customer and cloud provider security responsibilities leading to security gaps', 'Unclear Cloud Security Responsibilities', 'operational', 'open', '["CTL-001"]', '["OBL-001"]', '["TSK-001"]', '69f96d9a14a531eb0760657b', '2026-05-05T04:10:02.385000', '2026-05-05T04:14:30.383000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "treatment" = EXCLUDED."treatment", "risk_id" = EXCLUDED."risk_id", "likelihood" = EXCLUDED."likelihood", "risk_score" = EXCLUDED."risk_score", "frameworks" = EXCLUDED."frameworks", "treatment_plan" = EXCLUDED."treatment_plan", "impact" = EXCLUDED."impact", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "linked_control_ids" = EXCLUDED."linked_control_ids", "linked_obligation_ids" = EXCLUDED."linked_obligation_ids", "linked_task_ids" = EXCLUDED."linked_task_ids", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, 'POL-003', '["ISO27001","SOC2","ASAE3150","CDR"]', 'Establishes the methodology for identifying, assessing, treating and monitoring information security risks across the ISMS.', 'Risk Management Policy', NULL, '1.0', '<h1>Risk Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines the organisation''s approach to identifying, assessing, treating, monitoring and reporting information security risks. It establishes the methodology and governance structures necessary to maintain an Information Security Management System (ISMS) aligned with ISO/IEC 27001 Clauses 6.1 and 8, the SOC 2 Trust Services Criteria (CC3.1–CC3.4, CC9), the ASAE 3150 assurance framework, and the Competition and Consumer (Consumer Data Right) Rules 2020.</p><h2>2. Scope</h2><p>This policy applies to all information assets, business processes, personnel, systems, third parties and physical locations within the ISMS scope, including the Consumer Data Right (CDR) data environment. It covers strategic, operational, technical, third-party, legal/regulatory and physical risks that may affect the confidentiality, integrity or availability of information.</p><h2>3. Risk Management Principles</h2><ul><li><strong>Risk-based decision-making:</strong> Security investment shall be proportionate to the assessed risk;</li><li><strong>Documented and repeatable:</strong> The methodology shall be applied consistently across the organisation;</li><li><strong>Owned and accountable:</strong> Every risk shall have a single accountable owner;</li><li><strong>Continual improvement:</strong> The risk register and methodology shall be reviewed and improved over time;</li><li><strong>Aligned with business objectives:</strong> Risk treatment shall support the achievement of strategic and regulatory objectives.</li></ul><h2>4. Risk Assessment Methodology</h2><h3>4.1 Risk Identification</h3><p>Risks shall be identified through structured workshops, threat modelling, vulnerability assessments, audit findings, incident reviews, supplier assurance, regulatory horizon scanning, and ongoing monitoring of the threat landscape.</p><h3>4.2 Risk Analysis and Evaluation</h3><p>Each risk shall be analysed using a Likelihood (1–5) x Impact (1–5) scoring matrix against documented criteria covering financial, operational, regulatory and reputational impact. The resulting risk score shall be used to determine treatment priority and management approval thresholds.</p><h3>4.3 Risk Treatment</h3><p>Treatment options are: <em>mitigate, transfer, avoid</em> or <em>accept</em>. Where a control is selected, it shall be mapped to ISO 27001 Annex A and recorded in the Statement of Applicability (SoA). Residual risk shall be re-scored after treatment.</p><h3>4.4 Risk Acceptance</h3><p>Residual risks above the agreed appetite shall require formal written acceptance by the executive accountable owner and, for High/Critical residual risks, the CEO. Acceptance shall be time-bound and reviewed at least annually.</p><h2>5. Risk Register</h2><p>A central risk register shall be maintained capturing for each risk: identifier, title, description, category, owner, likelihood, impact, score, treatment, treatment plan, target date, residual score, status and linked controls/obligations. The register shall be reviewed quarterly by the Security Steering Committee.</p><h2>6. Risk Appetite</h2><p>The Board shall approve and annually review the organisation''s risk appetite statement, expressed in terms of acceptable likelihood and impact ranges per risk category. The CISO shall report exposure against appetite at each Management Review.</p><h2>7. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Board of Directors</td><td>Approve risk appetite; oversee risk posture</td></tr><tr><td>CEO</td><td>Approve High/Critical residual risk acceptance</td></tr><tr><td>CISO</td><td>Own methodology; maintain risk register; report quarterly</td></tr><tr><td>Risk Owners</td><td>Accountable for treatment plan execution within agreed timeline</td></tr><tr><td>Security Steering Committee</td><td>Quarterly review of register and treatment progress</td></tr><tr><td>Internal Audit</td><td>Independent assurance over the risk management process</td></tr></table><h2>8. Frequency and Triggers</h2><p>A formal enterprise risk assessment shall be performed at least annually. Targeted reassessments shall be triggered by: significant organisational or technology change, material incident, new regulatory obligation, significant supplier change, or audit finding.</p><h2>9. Compliance</h2><p>Non-compliance with this policy may result in disciplinary action and shall be reported to the CISO. Findings shall feed into the corrective action process.</p><h2>10. Policy Review</h2><p>This policy shall be reviewed at least annually by the CISO and approved by the CEO.</p><h2>11. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Clauses 6.1, 8.2, 8.3 and Annex A.5.4; SOC 2 CC3.1–CC3.4, CC9.1–CC9.2; ASAE 3150 control objectives for risk management; and CDR Privacy Safeguard 12 (Schedule 2 Part 1).</p>', '2027-05-01', 'risk_management', 'draft', '69f970995eaf8b697748c2a5', '2026-05-05T04:22:49.710000', '2026-05-05T04:42:46.802000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, 'POL-004', '["ISO27001","SOC2","CDR"]', 'Defines acceptable use of information assets and systems by personnel and contractors.', 'Acceptable Use Policy', NULL, '1.0', '<h1>Acceptable Use Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the rules and responsibilities for the acceptable use of the organisation''s information systems, networks, devices and data. It protects the organisation, its personnel, customers and partners from harms arising from inappropriate or unauthorised use.</p><h2>2. Scope</h2><p>This policy applies to all employees, contractors, consultants, temporary workers, interns and any other persons granted access to the organisation''s information assets, regardless of location. It covers organisation-owned and personally-owned devices used to access organisation systems or data.</p><h2>3. General Principles</h2><ul><li>Use of organisation systems is permitted for legitimate business purposes; limited and reasonable personal use is permitted provided it does not interfere with duties or breach this policy;</li><li>All activity on organisation systems may be logged, monitored and audited in accordance with applicable law;</li><li>Users shall not have an expectation of privacy when using organisation systems;</li><li>Users are personally accountable for activity performed under their accounts.</li></ul><h2>4. Permitted Use</h2><h3>4.1 Authorised Activities</h3><ul><li>Performing assigned business duties using organisation-approved systems and software;</li><li>Communicating with colleagues, customers and approved third parties using organisation channels;</li><li>Accessing approved cloud and SaaS services for business purposes.</li></ul><h3>4.2 Account and Credential Use</h3><ul><li>Each user shall use only their own uniquely identified account;</li><li>Credentials shall not be shared, written down in unsecured locations, or stored in browsers without an approved password manager;</li><li>Multi-Factor Authentication (MFA) shall not be bypassed or shared.</li></ul><h2>5. Prohibited Use</h2><ul><li>Installing unauthorised, pirated or unlicensed software;</li><li>Connecting unauthorised devices or removable media to organisation networks;</li><li>Disabling, bypassing or interfering with security controls (e.g. EDR, DLP, encryption);</li><li>Sending organisation data to personal email, personal cloud storage or unauthorised messaging apps;</li><li>Accessing material that is illegal, harassing, discriminatory or sexually explicit;</li><li>Conducting personal commercial activity, gambling, or activity that breaches law or contract;</li><li>Use of generative AI tools with sensitive, customer or CDR data without an approved exception;</li><li>Connecting to untrusted networks without VPN/ZTNA.</li></ul><h2>6. Device Security</h2><ul><li>All devices accessing organisation data shall be enrolled in the organisation''s endpoint management and EDR solution;</li><li>Full-disk encryption is mandatory; screens shall lock after no more than 10 minutes of inactivity;</li><li>Operating systems and software shall be kept up to date in accordance with the patching SLA;</li><li>Lost or stolen devices shall be reported to IT and the CISO immediately.</li></ul><h2>7. Communications</h2><ul><li>Email and messaging shall be used professionally and in accordance with classification handling requirements;</li><li>Sensitive information shall not be transmitted via unapproved channels;</li><li>External-facing content shall not disclose confidential or restricted information.</li></ul><h2>8. Workspace and Physical</h2><ul><li>Clear desk and clear screen practices shall be observed;</li><li>Visitors shall not be left unattended in restricted areas;</li><li>Printed sensitive information shall be securely stored and securely destroyed when no longer required.</li></ul><h2>9. Reporting Obligations</h2><p>Users shall promptly report suspected security incidents, phishing attempts, lost devices, accidental data disclosure, or breaches of this policy to the CISO via the incident reporting channel.</p><h2>10. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>All Users</td><td>Comply with this policy; report incidents</td></tr><tr><td>Line Managers</td><td>Reinforce policy; address breaches</td></tr><tr><td>HR</td><td>Embed policy in onboarding; manage disciplinary process</td></tr><tr><td>IT / Security</td><td>Implement technical controls; monitor for misuse</td></tr><tr><td>CISO</td><td>Own and maintain this policy</td></tr></table><h2>11. Compliance and Enforcement</h2><p>Breach of this policy may result in disciplinary action up to and including termination of employment or contract, and may give rise to civil or criminal liability. Significant or repeat breaches shall be reported to the CISO.</p><h2>12. Policy Review</h2><p>This policy shall be reviewed at least annually by the CISO and approved by the CEO.</p><h2>13. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.5.10, A.6.2, A.6.3, A.7.7, A.8.1, A.8.7; SOC 2 CC1.1, CC1.4, CC2.2, CC6.1; and CDR Privacy Safeguard 12.</p>', '2027-05-01', 'acceptable_use', 'draft', '69f970995eaf8b697748c2a6', '2026-05-05T04:22:49.710000', '2026-05-05T04:42:46.819000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Data Governance', 'CISO', NULL, 'POL-005', '["ISO27001","SOC2","ISO27018","CDR"]', 'Classifies information based on sensitivity and prescribes handling, labelling, transmission and disposal requirements.', 'Data Classification and Handling Policy', NULL, '1.0', '<h1>Data Classification and Handling Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Data Governance &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines how information is classified by sensitivity and the corresponding requirements for labelling, handling, transmission, storage, retention and disposal. Consistent classification is the foundation for proportionate, evidence-based information protection.</p><h2>2. Scope</h2><p>This policy applies to all information assets created, received, processed, stored or transmitted by the organisation in any format (digital, physical, verbal), and to all personnel and third parties handling such information. Special requirements apply to Consumer Data Right (CDR) data and personal information regulated under the Privacy Act 1988 (Cth).</p><h2>3. Classification Levels</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Level</th><th>Definition</th><th>Examples</th></tr><tr><td><strong>Public</strong></td><td>Information approved for public disclosure with no harm if disclosed</td><td>Marketing material, public website content</td></tr><tr><td><strong>Internal</strong></td><td>Information for internal business use; limited harm if disclosed</td><td>Internal procedures, organisation charts</td></tr><tr><td><strong>Confidential</strong></td><td>Sensitive business information; significant harm if disclosed</td><td>Customer data, financials, source code, contracts</td></tr><tr><td><strong>Restricted</strong></td><td>Highly sensitive or regulated information; severe harm if disclosed</td><td>CDR data, personal information, payment card data, authentication secrets, encryption keys</td></tr></table><h2>4. Classification Responsibilities</h2><ul><li>The Information Owner is accountable for classifying information assets they own;</li><li>All personnel are responsible for handling information according to its classification;</li><li>If classification is uncertain, the higher level shall be applied until reviewed;</li><li>Inherited data (e.g. derived datasets) inherits the highest classification of its sources.</li></ul><h2>5. Labelling Requirements</h2><ul><li>Confidential and Restricted documents shall display the classification in headers/footers;</li><li>Email containing Confidential/Restricted information shall use the approved classification banner;</li><li>System datasets containing Restricted information shall be tagged in the data catalogue;</li><li>Public and Internal materials may be left unlabelled where context makes the level clear.</li></ul><h2>6. Handling Requirements</h2><h3>6.1 Storage</h3><ul><li><strong>Public/Internal:</strong> approved corporate systems;</li><li><strong>Confidential:</strong> approved corporate systems with access controls; encryption at rest;</li><li><strong>Restricted:</strong> dedicated systems within defined boundary (CDR boundary for CDR data); encryption at rest with managed keys; access logging.</li></ul><h3>6.2 Transmission</h3><ul><li>All Confidential and Restricted data shall be transmitted using TLS 1.2 or higher;</li><li>Restricted data shall not be sent via personal channels, unencrypted email, or consumer file sharing;</li><li>Bulk export of Restricted data requires prior approval from the Data Owner and CISO.</li></ul><h3>6.3 Access</h3><ul><li>Access shall be granted on a need-to-know basis under the Access Control Policy;</li><li>Restricted data access shall be MFA-enforced and reviewed at least quarterly.</li></ul><h3>6.4 Printing and Physical</h3><ul><li>Restricted data shall not be printed unless strictly required and shall be securely destroyed (cross-cut shred or secure bin) immediately after use.</li></ul><h2>7. Retention and Disposal</h2><p>Information shall be retained only for as long as required by business need, contract, or law, and shall then be securely deleted or de-identified. CDR data shall be deleted or de-identified in accordance with CDR Privacy Safeguards 11 and 12 and the Retention Schedule. Disposal of physical media shall use NIST SP 800-88 compliant methods.</p><h2>8. CDR Data Specific Requirements</h2><ul><li>All CDR data is classified <strong>Restricted</strong> by default;</li><li>CDR data shall only be processed within the documented CDR data environment boundary;</li><li>CDR data shall not be combined with non-CDR data outside approved use cases;</li><li>Disclosure to third parties shall be permitted only where consistent with consumer consent and CDR Rules.</li></ul><h2>9. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Data Governance</td><td>Owns this policy; maintains classification scheme</td></tr><tr><td>Information Owners</td><td>Classify owned information; approve access</td></tr><tr><td>CISO</td><td>Approves controls and exceptions for Restricted data</td></tr><tr><td>All Users</td><td>Handle data according to classification</td></tr></table><h2>10. Compliance</h2><p>Non-compliance may lead to disciplinary action and shall be reported to the CISO. Material incidents shall be assessed against breach notification obligations.</p><h2>11. Policy Review</h2><p>This policy shall be reviewed at least annually by Data Governance and approved by the CISO.</p><h2>12. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.5.9–A.5.13, A.5.34, A.8.10–A.8.12; SOC 2 CC6.1, CC6.5, C1.1, C1.2; ISO/IEC 27018; and CDR Privacy Safeguards 11 and 12.</p>', '2027-05-01', 'data_protection', 'draft', '69f970995eaf8b697748c2a7', '2026-05-05T04:22:49.710000', '2026-05-05T04:42:46.833000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Incident Response Team', 'CISO', NULL, 'POL-006', '["ISO27001","SOC2","ISO27018","CDR"]', 'Defines the framework for detecting, responding to, recovering from and learning from security incidents.', 'Incident Response Policy', NULL, '1.0', '<h1>Incident Response Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Incident Response Team &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the framework for the timely, effective and consistent detection, response, recovery and post-incident review of information security incidents. It supports compliance with ISO/IEC 27001, SOC 2, ASAE 3150, the Notifiable Data Breaches (NDB) scheme under the Privacy Act 1988 (Cth), and the CDR Rules eligible data breach obligations.</p><h2>2. Scope</h2><p>This policy applies to all information security incidents affecting the organisation''s people, systems, data, customers, suppliers or services, including events affecting CDR data, personal information or critical operations.</p><h2>3. Definitions</h2><ul><li><strong>Event:</strong> An observable occurrence in a system or network;</li><li><strong>Security Incident:</strong> An event that has caused or has the potential to cause a breach of confidentiality, integrity or availability;</li><li><strong>Eligible Data Breach (NDB):</strong> Unauthorised access/disclosure or loss of personal information likely to result in serious harm;</li><li><strong>CDR Eligible Data Breach:</strong> Unauthorised access, disclosure or loss of CDR data per CDR Rules s 56.</li></ul><h2>4. Incident Response Phases</h2><h3>4.1 Preparation</h3><ul><li>Maintain documented playbooks for top scenarios (ransomware, BEC, credential theft, DDoS, third-party breach, CDR breach);</li><li>Maintain trained Incident Response Team (IRT) with on-call coverage;</li><li>Conduct tabletop exercise at least annually with documented learnings.</li></ul><h3>4.2 Identification and Triage</h3><ul><li>Detection sources include SIEM/EDR alerts, user reports, third-party notifications, and threat intelligence;</li><li>Triage shall classify severity within the response time SLA below.</li></ul><h3>4.3 Containment</h3><p>Short-term containment to limit damage (e.g. host isolation, credential rotation, blocking IOCs) shall be performed before evidence collection where required, with chain-of-custody preserved for forensics.</p><h3>4.4 Eradication</h3><p>Root cause shall be identified and remediated. Affected systems shall be rebuilt or sanitised before being returned to service.</p><h3>4.5 Recovery</h3><p>Restoration of services shall be validated, monitoring intensified, and customer/business impact communicated as appropriate.</p><h3>4.6 Lessons Learned</h3><p>A post-incident review shall be conducted within 14 calendar days of closure for Sev1/Sev2, with corrective actions tracked to completion.</p><h2>5. Severity Classification and SLAs</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Severity</th><th>Description</th><th>Initial Response</th><th>Executive Notification</th></tr><tr><td>Sev1</td><td>Critical breach, major outage, regulated data compromise</td><td>15 minutes</td><td>1 hour</td></tr><tr><td>Sev2</td><td>Significant impact; partial service or limited data exposure</td><td>1 hour</td><td>4 hours</td></tr><tr><td>Sev3</td><td>Limited impact, no regulated data exposure</td><td>4 hours</td><td>Daily summary</td></tr><tr><td>Sev4</td><td>Minor / informational</td><td>Next business day</td><td>Weekly summary</td></tr></table><h2>6. Notification Obligations</h2><ul><li><strong>NDB Scheme (Privacy Act):</strong> Notify OAIC and affected individuals as soon as practicable where an eligible data breach is identified;</li><li><strong>CDR Eligible Data Breach:</strong> Notify ACCC, OAIC and affected consumers in accordance with CDR Rules s 56 and the breach response playbook;</li><li><strong>Customers:</strong> Notify per contractual SLAs and assurance commitments;</li><li><strong>Regulators / Law Enforcement:</strong> Engage as required by jurisdiction.</li></ul><h2>7. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Incident Commander</td><td>Overall coordination of response</td></tr><tr><td>CISO</td><td>Executive accountability; regulator engagement</td></tr><tr><td>DPO / Privacy Officer</td><td>Privacy assessment; NDB / CDR breach decisions</td></tr><tr><td>Legal</td><td>Legal advice; privilege; regulator liaison</td></tr><tr><td>Communications</td><td>Internal and external messaging</td></tr><tr><td>IRT Engineers</td><td>Technical containment, eradication, recovery</td></tr><tr><td>HR</td><td>Insider-related incidents</td></tr></table><h2>8. Evidence Handling</h2><p>All evidence shall be collected, transported, stored and destroyed under documented chain-of-custody. Forensic copies shall be made before remediation where feasible.</p><h2>9. Testing and Improvement</h2><p>The IRT shall conduct at least one tabletop exercise per year and one technical simulation per year. Findings shall be tracked through to closure and feed into policy and playbook updates.</p><h2>10. Compliance</h2><p>Failure to follow this policy may impair the organisation''s ability to meet legal and regulatory obligations and may result in disciplinary action.</p><h2>11. Policy Review</h2><p>This policy shall be reviewed at least annually and after every Sev1 incident.</p><h2>12. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.5.24–A.5.28, A.6.8; SOC 2 CC7.3–CC7.5; ASAE 3150 incident management control objectives; the NDB scheme under the Privacy Act 1988; and CDR Rules s 56.</p>', '2027-05-01', 'incident_response', 'draft', '69f970995eaf8b697748c2a8', '2026-05-05T04:22:49.710000', '2026-05-05T04:42:46.857000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Business Continuity Manager', 'CEO', NULL, 'POL-007', '["ISO27001","SOC2","CDR"]', 'Defines requirements for ensuring continuity of operations and recovery from disasters.', 'Business Continuity and Disaster Recovery Policy', NULL, '1.0', '<h1>Business Continuity and Disaster Recovery Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Business Continuity Manager &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the framework for ensuring continuity of critical business operations and the recovery of information systems following disruptive events. It supports the resilience commitments made to customers, regulators and stakeholders, and aligns with ISO/IEC 27001 Annex A.5.29–A.5.30 and SOC 2 Availability criteria (A1.1–A1.3).</p><h2>2. Scope</h2><p>This policy applies to all critical business processes, supporting information systems, third-party dependencies, premises and personnel necessary to deliver the organisation''s products and services, including services within the Consumer Data Right (CDR) data environment.</p><h2>3. Objectives</h2><ul><li>Maintain continuity of critical services within agreed Recovery Time Objectives (RTO);</li><li>Limit data loss to within agreed Recovery Point Objectives (RPO);</li><li>Protect personnel safety as the highest priority during disruption;</li><li>Meet regulatory and contractual continuity obligations;</li><li>Continuously improve resilience based on tests and incidents.</li></ul><h2>4. Business Impact Analysis (BIA)</h2><p>A BIA shall be performed at least annually and following material change. The BIA shall identify critical business processes, supporting assets, dependencies, maximum tolerable period of disruption, RTO, RPO and minimum business continuity objective for each.</p><h2>5. Recovery Targets</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Service Tier</th><th>RTO</th><th>RPO</th></tr><tr><td>Tier 1 (Critical / customer-facing / CDR)</td><td>≤ 4 hours</td><td>≤ 15 minutes</td></tr><tr><td>Tier 2 (Important)</td><td>≤ 24 hours</td><td>≤ 4 hours</td></tr><tr><td>Tier 3 (Standard)</td><td>≤ 72 hours</td><td>≤ 24 hours</td></tr><tr><td>Tier 4 (Non-essential)</td><td>≤ 7 days</td><td>≤ 7 days</td></tr></table><h2>6. Architecture and Controls</h2><ul><li>Critical systems shall be deployed across multiple availability zones with automated failover;</li><li>Backups shall be encrypted, geographically separated and immutable where supported;</li><li>Capacity planning shall ensure peak load can be sustained;</li><li>DDoS protection, WAF and edge resilience shall be in place for internet-facing services.</li></ul><h2>7. Plans</h2><ul><li><strong>Business Continuity Plan (BCP):</strong> Defines manual workarounds, alternate locations and personnel arrangements;</li><li><strong>Disaster Recovery Plan (DRP):</strong> Defines technical procedures for system recovery;</li><li><strong>Crisis Communications Plan:</strong> Defines internal/external communications during disruption.</li></ul><h2>8. Testing</h2><ul><li>BCP tabletop exercise: at least annually;</li><li>DR technical recovery test for Tier 1 systems: at least annually with documented success against RTO/RPO;</li><li>Backup restore test: at least quarterly for Tier 1 data;</li><li>Test results, deviations and corrective actions shall be documented and tracked.</li></ul><h2>9. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>CEO</td><td>Approve BCP strategy and risk appetite</td></tr><tr><td>Business Continuity Manager</td><td>Own programme, BIA, plans and testing</td></tr><tr><td>Service Owners</td><td>Maintain DR runbooks for owned systems</td></tr><tr><td>CISO</td><td>Ensure security of recovery and continuity controls</td></tr><tr><td>HR / Facilities</td><td>People and premises continuity</td></tr></table><h2>10. Suppliers and Third Parties</h2><p>Continuity dependencies on suppliers (including subservice organisations under ASAE 3150) shall be documented, and contractual continuity commitments verified during vendor due diligence and annual review.</p><h2>11. Compliance</h2><p>This policy is mandatory. Non-compliance shall be reported to the Business Continuity Manager and CISO and may trigger corrective action.</p><h2>12. Policy Review</h2><p>This policy shall be reviewed at least annually and after any major incident or material change.</p><h2>13. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.5.29, A.5.30, A.8.13, A.8.14; SOC 2 A1.1–A1.3, CC7.5; and ASAE 3150 control objectives for availability and recovery.</p>', '2027-05-01', 'business_continuity', 'draft', '69f970995eaf8b697748c2a9', '2026-05-05T04:22:49.710000', '2026-05-05T04:42:46.869000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Change Manager', 'CTO', NULL, 'POL-008', '["ISO27001","SOC2"]', 'Governs how changes to systems, applications, infrastructure and processes are authorised, tested and deployed.', 'Change Management Policy', NULL, '1.0', '<h1>Change Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Change Manager &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy ensures that all changes to information systems, applications, infrastructure, security configurations and supporting processes are authorised, risk-assessed, tested, documented and reviewable. It supports SOC 2 CC8.1, ISO/IEC 27001 Annex A.8.32 and ASAE 3150 control objectives.</p><h2>2. Scope</h2><p>This policy applies to all changes affecting production systems, customer-facing services, security controls, data, identity systems and any system within the CDR data environment. It covers application code, infrastructure-as-code, configuration, schema, network, identity and supplier-managed systems.</p><h2>3. Change Categories</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Category</th><th>Description</th><th>Approval</th></tr><tr><td>Standard</td><td>Pre-approved, low-risk, repeatable changes (e.g. routine patching)</td><td>Pre-approved category owner</td></tr><tr><td>Normal</td><td>Non-routine changes requiring assessment</td><td>Change Advisory Board (CAB)</td></tr><tr><td>Emergency</td><td>Required to restore service or address active threat</td><td>Emergency CAB; post-implementation review mandatory</td></tr></table><h2>4. Change Lifecycle</h2><h3>4.1 Request and Risk Assessment</h3><p>Changes shall be raised in the change management system with: description, rationale, scope, risk assessment, security impact, rollback plan, test evidence and verification plan.</p><h3>4.2 Approval</h3><p>Approvals shall be recorded electronically. Production changes require approval by the change owner and (for Normal changes) the CAB. Security-impacting changes require CISO or delegate approval.</p><h3>4.3 Testing</h3><ul><li>Functional and regression testing for application changes;</li><li>Security testing (SAST/DAST/SCA) per Secure SDLC Policy;</li><li>Performance and capacity testing for high-load changes;</li><li>Test evidence shall be attached to the change record.</li></ul><h3>4.4 Implementation</h3><ul><li>Implementation shall follow the documented plan and maintenance window;</li><li>Segregation of duties: developers shall not unilaterally deploy to production; deployments shall be performed via the CI/CD pipeline with approvals enforced.</li></ul><h3>4.5 Verification and Closure</h3><p>Post-deployment verification, monitoring window observation, and closure with outcome (success/rollback/partial) shall be recorded.</p><h2>5. Emergency Changes</h2><p>Emergency changes may be implemented with verbal approval from the on-call Incident Commander and CISO/delegate, but shall be documented in the change system within 24 hours and undergo post-implementation review.</p><h2>6. Segregation of Duties</h2><ul><li>Developers cannot self-approve their own production changes;</li><li>Production deployment credentials shall not be shared with developers;</li><li>Privileged production access for change activity shall be just-in-time and audited.</li></ul><h2>7. Logging and Audit</h2><p>All change activity, approvals and deployment events shall be logged centrally and retained for at least 12 months. Logs shall be tamper-resistant and reviewed during access reviews and audits.</p><h2>8. Configuration Management</h2><p>Production configuration shall be managed as code where feasible, version-controlled, and synchronised between environments. Configuration drift shall be detected and remediated.</p><h2>9. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Change Manager</td><td>Owns process; chairs CAB</td></tr><tr><td>CAB</td><td>Reviews and approves Normal changes</td></tr><tr><td>Change Initiator</td><td>Submits, plans, and verifies the change</td></tr><tr><td>CISO</td><td>Approves security-impacting changes</td></tr><tr><td>Service Owners</td><td>Accept production deployment for owned services</td></tr></table><h2>10. Compliance</h2><p>Unauthorised changes are prohibited. Detected unauthorised changes shall be treated as a security incident under the Incident Response Policy.</p><h2>11. Policy Review</h2><p>This policy shall be reviewed at least annually.</p><h2>12. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.8.32 (and related A.8.27–A.8.31); SOC 2 CC8.1; and ASAE 3150 control objectives for change management.</p>', '2027-05-01', 'change_management', 'draft', '69f970995eaf8b697748c2aa', '2026-05-05T04:22:49.710000', '2026-05-05T04:42:46.880000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Vendor Manager', 'CISO', NULL, 'POL-009', '["ISO27001","SOC2","ISO27017","ISO27018","CDR","ASAE3150"]', 'Establishes due diligence, contracting and monitoring requirements for vendors and third parties.', 'Vendor and Third-Party Risk Management Policy', NULL, '1.0', '<h1>Vendor and Third-Party Risk Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Vendor Manager &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the requirements for the identification, assessment, contracting, onboarding, monitoring and offboarding of vendors and other third parties. It manages the risks introduced by suppliers to the confidentiality, integrity and availability of organisation and customer data, and supports ISO/IEC 27001, SOC 2, ASAE 3150 (subservice organisations) and CDR Rules supplier governance requirements.</p><h2>2. Scope</h2><p>This policy applies to all third parties (vendors, suppliers, contractors, subprocessors, outsourced service providers and subservice organisations) that process organisation data, integrate with organisation systems, or deliver services material to the organisation''s operations — including those within the CDR data environment.</p><h2>3. Vendor Tiering</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Tier</th><th>Criteria</th><th>Required Assurance</th></tr><tr><td>Tier 1 – Critical</td><td>Hosts/processes Restricted data (incl. CDR/PII), critical operational dependency, or subservice organisation</td><td>SOC 2 Type II / ISO 27001 cert; signed DPA; annual review; incident notification SLA</td></tr><tr><td>Tier 2 – High</td><td>Processes Confidential data or material business dependency</td><td>Security questionnaire; contract security clauses; annual review</td></tr><tr><td>Tier 3 – Moderate</td><td>Limited access to Internal data only</td><td>Basic due diligence; standard terms</td></tr><tr><td>Tier 4 – Low</td><td>No data access; non-material</td><td>Standard procurement only</td></tr></table><h2>4. Pre-Engagement Due Diligence</h2><ul><li>Business case and risk assessment by requesting team;</li><li>Vendor questionnaire scaled to tier (security, privacy, financial, ESG, sanctions);</li><li>Review of independent assurance (SOC 2/ISO/PCI/HIPAA) where applicable;</li><li>Verification of insurance, regulatory standing and incident history;</li><li>Approval by Vendor Manager and (Tier 1/2) CISO and Privacy Officer.</li></ul><h2>5. Contracting Requirements</h2><ul><li>Mandatory clauses: confidentiality, security obligations, audit/inspection rights, sub-processor approval, breach notification within agreed SLA, data return/deletion on termination, liability and indemnity;</li><li>Data Processing Agreement (DPA) for any vendor processing personal information;</li><li>Standard Contractual Clauses (or other lawful mechanism) for international transfers;</li><li>For CDR-relevant vendors: requirements aligned to CDR Privacy Safeguards 6, 11, 12 and CDR Rules.</li></ul><h2>6. Onboarding</h2><ul><li>Provisioning per least privilege; MFA-enforced;</li><li>Integration security review (IP allow-listing, mTLS, scoped tokens, scope of access logged);</li><li>Vendor record created in CMDB with owner, criticality and applicable frameworks.</li></ul><h2>7. Ongoing Monitoring</h2><ul><li>Annual reassessment for Tier 1/2 vendors with refreshed SOC/ISO reports and questionnaires;</li><li>Continuous monitoring of incident notifications and threat intelligence;</li><li>Service performance and SLA reviews at agreed cadence;</li><li>Subservice organisations under ASAE 3150 / SOC 2 documented with carve-out method or inclusive evidence and CUEC schedule.</li></ul><h2>8. Subservice Organisations and Subprocessors</h2><p>Subservice organisations relied upon for the assurance scope shall be identified, documented and disclosed to assurance practitioners and customers as required. Engagement of new subprocessors handling personal information shall be notified to customers per contract.</p><h2>9. Offboarding</h2><ul><li>Documented offboarding checklist covering access revocation, data return/deletion (with attestation), key rotation and contract closure;</li><li>Verification of deletion of organisation data within agreed timeframe.</li></ul><h2>10. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Vendor Manager</td><td>Owns vendor lifecycle and tier register</td></tr><tr><td>CISO</td><td>Approves Tier 1/2 vendors; reviews assurance reports</td></tr><tr><td>Privacy Officer / DPO</td><td>Approves DPAs and privacy aspects</td></tr><tr><td>Legal / Procurement</td><td>Negotiates contracts</td></tr><tr><td>Service Owner</td><td>Day-to-day relationship and operational oversight</td></tr></table><h2>11. Compliance</h2><p>Engaging vendors outside this policy is prohibited and shall be treated as a control deficiency. Material vendor incidents shall be escalated under the Incident Response Policy.</p><h2>12. Policy Review</h2><p>This policy shall be reviewed at least annually.</p><h2>13. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.5.19–A.5.23, A.5.34; SOC 2 CC9.2; ASAE 3150 subservice organisation requirements; ISO/IEC 27017 and 27018 cloud and personal data principles; and CDR Rules supplier provisions.</p>', '2027-05-01', 'vendor_management', 'draft', '69f970995eaf8b697748c2ab', '2026-05-05T04:22:49.710000', '2026-05-05T04:42:46.891000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('HR', 'CISO', NULL, 'POL-010', '["ISO27001","SOC2","CDR"]', 'Defines security requirements through the employment lifecycle.', 'Human Resources Security Policy', NULL, '1.0', '<h1>Human Resources Security Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> HR &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines the information security requirements that apply throughout the employment lifecycle – prior to, during, and on change or termination of employment – to reduce the risk of human-related security breaches and to support compliance with ISO/IEC 27001 Annex A.6, SOC 2 CC1.4 / CC1.5 and CDR fit-and-proper obligations.</p><h2>2. Scope</h2><p>This policy applies to all employees, contractors, consultants, interns, temporary workers and any other personnel performing work for the organisation, in any location, including those with access to the CDR data environment.</p><h2>3. Pre-Employment</h2><h3>3.1 Background Screening</h3><p>Background checks shall be performed prior to commencement, proportionate to the role and access required. For roles with access to Restricted data (including CDR data), background checks shall include identity verification, right-to-work, criminal history, and where appropriate financial probity and references. CDR-relevant associated persons shall meet the CDR fit-and-proper requirements (CDR Rules s 5.12).</p><h3>3.2 Contractual Obligations</h3><p>Employment and contractor agreements shall include confidentiality, intellectual property, acceptable use, code of conduct, conflict of interest, and ongoing post-termination obligations. Specific clauses shall apply to handling of personal and CDR data.</p><h2>4. During Employment</h2><h3>4.1 Security Awareness and Training</h3><ul><li>Mandatory security awareness training within 30 days of commencement and annually thereafter;</li><li>Targeted role-based training (e.g. secure development, privileged access, CDR data handling);</li><li>Quarterly phishing simulations with remedial training for repeat clickers;</li><li>Completion rate target ≥ 95% – reported to management.</li></ul><h3>4.2 Performance and Conduct</h3><p>Information security responsibilities shall be reflected in role descriptions and performance feedback where relevant. Breaches of security policy shall be addressed through the disciplinary process.</p><h3>4.3 Role Changes</h3><p>On change of role, access shall be re-evaluated using the joiner-mover-leaver (JML) process; access no longer required shall be removed within 5 business days.</p><h2>5. Termination and Change of Engagement</h2><ul><li>Same-day revocation of access on termination (or sooner if security risk);</li><li>Return of all organisation assets (laptops, mobile devices, tokens, badges, documents);</li><li>Exit interview to remind of ongoing obligations and reporting channels;</li><li>For privileged roles, additional review of recent activity logs and credential rotation.</li></ul><h2>6. Disciplinary Process</h2><p>A formal disciplinary process shall apply to personnel who breach this policy or related policies. The process shall be fair, documented, proportionate and consider the severity of the breach.</p><h2>7. Contractors and Third-Party Personnel</h2><p>Contractors shall be subject to equivalent screening, training and access governance as employees, proportionate to the role. Third-party personnel records shall be managed by the engaging service owner with HR oversight.</p><h2>8. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>HR</td><td>Owns this policy; manages screening and disciplinary process</td></tr><tr><td>CISO</td><td>Defines training and access requirements</td></tr><tr><td>Hiring Managers</td><td>Confirm role security requirements; approve access</td></tr><tr><td>IT</td><td>Provisioning and revocation per JML process</td></tr><tr><td>All Personnel</td><td>Comply with this policy and supporting policies</td></tr></table><h2>9. Compliance</h2><p>Non-compliance may result in disciplinary action up to and including termination. Significant breaches shall be reported to the CISO and may be treated as a security incident.</p><h2>10. Policy Review</h2><p>This policy shall be reviewed at least annually and on material legislative or organisational change.</p><h2>11. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.6.1–A.6.6; SOC 2 CC1.4, CC1.5, CC2.2; and CDR fit-and-proper requirements (CDR Rules s 5.12).</p>', '2027-05-01', 'hr_security', 'draft', '69f970995eaf8b697748c2ac', '2026-05-05T04:22:49.710000', '2026-05-05T04:45:25.176000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Security Architecture', 'CISO', NULL, 'POL-011', '["ISO27001","SOC2","ISO27018","CDR"]', 'Defines approved cryptographic algorithms, key management practices and TLS standards.', 'Cryptography and Key Management Policy', NULL, '1.0', '<h1>Cryptography and Key Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Security Architecture &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the approved cryptographic algorithms, protocols and key management practices used to protect the confidentiality, integrity and authenticity of information. It supports ISO/IEC 27001 Annex A.8.24, SOC 2 CC6.1 and CC6.7, ISO/IEC 27018, and CDR Privacy Safeguard 12 (Schedule 2 Part 1).</p><h2>2. Scope</h2><p>This policy applies to all cryptographic use within the organisation, including cryptography in transit, at rest, in use, in code, in identity systems, and in third-party services that protect organisation or CDR data.</p><h2>3. Approved Algorithms and Protocols</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Purpose</th><th>Approved</th><th>Prohibited</th></tr><tr><td>Symmetric encryption</td><td>AES-256 (GCM preferred)</td><td>DES, 3DES, RC4</td></tr><tr><td>Asymmetric encryption</td><td>RSA ≥ 2048 bit; ECC P-256 / P-384</td><td>RSA &lt; 2048; DSA &lt; 2048</td></tr><tr><td>Hashing</td><td>SHA-256, SHA-384, SHA-512</td><td>MD5, SHA-1</td></tr><tr><td>Password hashing</td><td>Argon2id, bcrypt, PBKDF2-HMAC-SHA256</td><td>Plain hashing without salt</td></tr><tr><td>Transport</td><td>TLS 1.2 (with secure ciphers) minimum; TLS 1.3 preferred</td><td>SSLv3, TLS 1.0, TLS 1.1</td></tr><tr><td>Email transport</td><td>TLS, MTA-STS, DMARC, DKIM</td><td>Cleartext SMTP for sensitive data</td></tr></table><h2>4. Use Requirements</h2><ul><li>All Confidential and Restricted data shall be encrypted at rest using approved algorithms;</li><li>All data in transit across untrusted networks shall be encrypted using approved protocols;</li><li>CDR data, personal information and authentication secrets shall always be encrypted at rest with managed keys;</li><li>Hard-coded keys, secrets or credentials in source code, configuration or images are prohibited.</li></ul><h2>5. Key Management</h2><h3>5.1 Generation</h3><p>Keys shall be generated using approved cryptographically secure random number generators. Where supported, generation shall occur within an HSM or managed KMS.</p><h3>5.2 Storage</h3><p>Keys shall be stored in the centralised Key Management Service (KMS) or HSM. Application code shall reference keys by ID and never persist key material outside the KMS/HSM.</p><h3>5.3 Distribution and Access</h3><p>Access to keys shall be governed by least-privilege IAM, MFA-enforced, logged and reviewed at least quarterly. Separation of duties shall apply between key custodians and users.</p><h3>5.4 Rotation</h3><ul><li>Data encryption keys: rotated at least annually and immediately on suspected compromise;</li><li>TLS certificates: lifetimes shall comply with public CA limits (≤ 13 months for public, internal per architecture standards);</li><li>API keys, tokens and service credentials: rotated at least annually and on personnel changes;</li><li>Root keys: rotated per HSM/KMS vendor recommendation.</li></ul><h3>5.5 Backup and Recovery</h3><p>Key material shall be backed up using HSM/KMS-supported export controls under multi-party authorisation, stored in geographically separated secure locations, and tested for recovery at least annually.</p><h3>5.6 Destruction</h3><p>Decommissioned keys shall be destroyed using HSM/KMS-supported destroy operations with confirmation of zeroisation and audit log evidence.</p><h2>6. Code, Secrets and Pipelines</h2><ul><li>Secrets shall be stored in approved secret management tooling (e.g. HashiCorp Vault, AWS Secrets Manager);</li><li>CI/CD pipelines shall retrieve secrets at runtime; never embed in repos or images;</li><li>Pre-commit and SAST/secret-scan tooling shall block secrets from entering source control.</li></ul><h2>7. Customer-Managed and Third-Party Keys</h2><p>Where customer-managed encryption keys (CMEK) or BYOK arrangements are offered, the responsibilities and operational procedures shall be documented in the customer agreement and runbooks. Third-party providers handling keys shall hold appropriate certifications.</p><h2>8. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Security Architecture</td><td>Owns standards and approved algorithms</td></tr><tr><td>CISO</td><td>Approves exceptions; reviews compliance</td></tr><tr><td>Key Custodians</td><td>Operate KMS/HSM under SoD</td></tr><tr><td>Engineering</td><td>Implement cryptography per this policy</td></tr></table><h2>9. Exceptions</h2><p>Exceptions require written CISO approval, documented compensating controls, and a remediation plan with target date.</p><h2>10. Compliance</h2><p>Use of unapproved cryptography or insecure key handling shall be treated as a control failure and may be a security incident.</p><h2>11. Policy Review</h2><p>This policy shall be reviewed at least annually and as cryptographic standards evolve.</p><h2>12. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.8.24; SOC 2 CC6.1, CC6.7, C1.1; ISO/IEC 27018; and CDR Privacy Safeguard 12 (Schedule 2 Part 1).</p>', '2027-05-01', 'cryptography', 'draft', '69f970995eaf8b697748c2ad', '2026-05-05T04:22:49.710000', '2026-05-05T04:45:25.221000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Engineering / AppSec', 'CTO', NULL, 'POL-012', '["ISO27001","SOC2"]', 'Defines secure SDLC requirements, code review, testing and dependency management.', 'Secure Software Development Policy', NULL, '1.0', '<h1>Secure Software Development Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Engineering / AppSec &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines the secure software development lifecycle (SDLC) requirements that ensure security is designed, built, tested and maintained in all software developed or materially configured by the organisation. It supports ISO/IEC 27001 Annex A.8.25–A.8.34 and SOC 2 CC7.1, CC8.1.</p><h2>2. Scope</h2><p>This policy applies to all in-house developed software, infrastructure-as-code, configuration-as-code, integrations and customisations of third-party platforms that support the organisation''s services or interact with Confidential or Restricted data, including the CDR data environment.</p><h2>3. SDLC Requirements</h2><h3>3.1 Requirements and Design</h3><ul><li>Security requirements shall be elicited during requirements definition;</li><li>Threat modelling (e.g. STRIDE) shall be performed for new services and material design changes, with documented mitigations;</li><li>Privacy-by-design and data minimisation principles shall be applied for any feature processing personal or CDR data.</li></ul><h3>3.2 Coding Standards</h3><ul><li>Engineers shall follow approved secure coding standards aligned with OWASP Top 10, OWASP ASVS, and language-specific guidance;</li><li>Input validation, output encoding, parameterised queries, and safe deserialisation are mandatory;</li><li>Secrets and credentials shall not be embedded in code (see Cryptography Policy).</li></ul><h3>3.3 Code Review</h3><ul><li>All production-bound changes shall undergo peer review by an engineer other than the author;</li><li>Reviews shall consider security, correctness, performance, maintainability and test coverage;</li><li>Security-sensitive changes shall require AppSec or Security Architect review.</li></ul><h3>3.4 Automated Security Testing</h3><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Stage</th><th>Tooling</th><th>Required</th></tr><tr><td>Pre-commit</td><td>Secret scanning, linters</td><td>Yes</td></tr><tr><td>CI</td><td>SAST, SCA (dependency vulnerability scan)</td><td>Yes</td></tr><tr><td>Pre-deploy</td><td>Container/IaC scanning</td><td>Yes</td></tr><tr><td>Post-deploy</td><td>DAST against staging or pre-prod</td><td>Tier 1 services</td></tr></table><h3>3.5 Vulnerability Management in SDLC</h3><ul><li>Critical and High findings shall block the merge or release;</li><li>Medium findings shall be tracked with risk-based remediation timeline;</li><li>Software Bill of Materials (SBOM) shall be generated for releases of Tier 1 services.</li></ul><h3>3.6 Build, Release and Deployment</h3><ul><li>Builds shall occur in trusted, ephemeral CI environments;</li><li>Artefacts shall be signed and stored in trusted registries;</li><li>Production deployment shall be gated by automated checks, approvals and the Change Management Policy;</li><li>Segregation of duties shall be enforced (developers cannot self-approve production deploys).</li></ul><h3>3.7 Operational Security</h3><ul><li>Logging and monitoring per the Logging and Monitoring Policy;</li><li>Feature flags and progressive rollout for risk reduction;</li><li>Defined rollback strategy for every release.</li></ul><h2>4. Penetration Testing</h2><p>Independent penetration testing shall be performed at least annually for production-facing applications and APIs (and after material change), with findings tracked through to remediation. CDR-bounded services shall be included in scope.</p><h2>5. Training</h2><p>Engineers shall complete secure development training annually, with role-specific content (front-end, back-end, mobile, infrastructure-as-code, AI). Champions shall be identified per team.</p><h2>6. Open Source and Third-Party Components</h2><ul><li>All third-party components shall be approved and tracked in the SBOM;</li><li>Vulnerable components shall be remediated per the vulnerability management SLA;</li><li>Licences shall be reviewed for compatibility.</li></ul><h2>7. AI and Generative Code</h2><p>Use of AI coding assistants is permitted under approved tooling only. Generated code remains the responsibility of the engineer and shall be reviewed under the same standards as human-written code. Customer or CDR data shall not be sent to third-party AI services without an approved exception.</p><h2>8. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>CTO / VP Engineering</td><td>Resourcing and accountability for secure SDLC</td></tr><tr><td>AppSec / Security Architecture</td><td>Standards, tooling, threat modelling, exceptions</td></tr><tr><td>Engineering Managers</td><td>Enforce SDLC compliance in their teams</td></tr><tr><td>Engineers</td><td>Apply secure coding and testing</td></tr><tr><td>CISO</td><td>Approves material risk exceptions</td></tr></table><h2>9. Compliance</h2><p>Non-compliance shall result in build/release blockers and may trigger corrective action under the disciplinary process.</p><h2>10. Policy Review</h2><p>This policy shall be reviewed at least annually.</p><h2>11. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.8.25–A.8.34; SOC 2 CC7.1, CC8.1; OWASP ASVS; and supports CDR Privacy Safeguard 12 obligations applicable to the CDR data environment.</p>', '2027-05-01', 'operations_security', 'draft', '69f970995eaf8b697748c2ae', '2026-05-05T04:22:49.710000', '2026-05-05T04:45:25.234000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('DPO', 'CEO', NULL, 'POL-013', '["CDR"]', 'Public-facing CDR Policy required by Privacy Safeguard 1 describing collection, use, disclosure and management of CDR data.', 'CDR Policy', NULL, '1.0', '<h1>CDR Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Data Protection Officer &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. About This Policy</h2><p>This Consumer Data Right (CDR) Policy is published to satisfy Privacy Safeguard 1 (open and transparent management of CDR data) under Schedule 2 of the Competition and Consumer Act 2010 (Cth) and the Competition and Consumer (Consumer Data Right) Rules 2020 (CDR Rules). It explains how the organisation manages CDR data, the rights of CDR consumers, and how complaints can be raised.</p><h2>2. Definitions</h2><ul><li><strong>CDR data</strong> means data within the meaning of section 56AI of the Competition and Consumer Act 2010 (Cth) and includes any information derived from CDR data;</li><li><strong>CDR consumer</strong> means an individual or entity to whom CDR data relates and who may share that data using the CDR;</li><li><strong>Accredited Data Recipient (ADR)</strong> means a person accredited by the ACCC under the CDR Rules;</li><li><strong>Designated Sectors</strong> include banking, energy and (over time) other sectors as designated by the Treasurer.</li></ul><h2>3. Categories of CDR Data Collected and Held</h2><p>The categories of CDR data that may be collected and held depend on the consumer''s authorisation and may include account data, transaction data, customer data and product data permitted under the relevant designation instrument.</p><h2>4. Purposes of Collection and Use</h2><p>CDR data is collected and used only:</p><ul><li>For the specific purposes consented to by the CDR consumer;</li><li>For directly related secondary purposes permitted under the CDR Rules;</li><li>To meet legal obligations;</li><li>To prevent or investigate fraud or unlawful activity, where permitted.</li></ul><h2>5. How Consent Is Obtained, Managed and Withdrawn</h2><ul><li>Consent is express, voluntary, time-limited and specific, in line with the CDR Rules and the Data Standards (CX Standards);</li><li>Consumers are presented with a consent dashboard to view, amend or withdraw consents at any time;</li><li>On withdrawal, the organisation ceases collection and uses the CDR data only as permitted by the CDR Rules, and de-identifies or deletes data in accordance with Privacy Safeguard 12 and the Retention Schedule.</li></ul><h2>6. Disclosure of CDR Data</h2><p>CDR data is disclosed only:</p><ul><li>To Accredited Data Recipients or persons authorised by the consumer;</li><li>As required or authorised by law;</li><li>In accordance with the consumer''s express consent and the CDR Rules.</li></ul><p>The organisation does not disclose CDR data overseas other than as permitted by the consumer''s consent and the CDR Rules.</p><h2>7. Storage, Security and Retention</h2><ul><li>CDR data is held within the organisation''s defined CDR data environment subject to the controls required by Privacy Safeguard 12 and CDR Rules Schedule 2;</li><li>CDR data is encrypted at rest and in transit, access is MFA-enforced and least-privilege, and activity is logged and monitored;</li><li>Retention is limited to the period for which consent was given or as required by law; on expiry data is deleted or de-identified.</li></ul><h2>8. Consumer Rights</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Right</th><th>How to Exercise</th></tr><tr><td>Access CDR data we hold (PS 11/12)</td><td>Through the consent dashboard or by contacting the DPO</td></tr><tr><td>Correction (PS 13)</td><td>Submit a request to the DPO; the organisation will respond as soon as practicable</td></tr><tr><td>Withdraw consent</td><td>Through the consent dashboard at any time</td></tr><tr><td>Request deletion / de-identification</td><td>Through the consent dashboard or DPO</td></tr></table><h2>9. Complaints and Dispute Resolution</h2><p>CDR-related complaints can be lodged with the organisation''s Data Protection Officer. The organisation operates an Internal Dispute Resolution (IDR) process consistent with ASIC RG 271 and CDR Rules timeframes. Unresolved complaints can be escalated to the Australian Financial Complaints Authority (AFCA) as the approved External Dispute Resolution (EDR) scheme. Privacy complaints can also be made to the Office of the Australian Information Commissioner (OAIC).</p><h2>10. Eligible Data Breach Notification</h2><p>If an eligible data breach involving CDR data occurs, the organisation will notify the ACCC, OAIC and affected CDR consumers in accordance with section 56 of the CDR Rules and the Notifiable Data Breaches scheme under the Privacy Act 1988 (Cth).</p><h2>11. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>CEO</td><td>Executive accountability for CDR compliance</td></tr><tr><td>DPO</td><td>Owns this policy; consumer rights handling</td></tr><tr><td>CISO</td><td>Privacy Safeguard 12 (information security)</td></tr><tr><td>Compliance Manager</td><td>Accreditation and ACCC reporting</td></tr><tr><td>Legal</td><td>Interpretation of CDR Rules and contracts</td></tr></table><h2>12. Contacting Us</h2><p>For questions about this Policy or to exercise your rights, contact the Data Protection Officer using the contact details on the organisation''s public website. Updates to this policy will be published on the same website with an effective date.</p><h2>13. Policy Review</h2><p>This policy shall be reviewed at least annually and on material change to the CDR Rules, designations or organisational arrangements.</p><h2>14. Related Obligations</h2><p>This policy supports compliance with CDR Privacy Safeguards 1, 3, 6, 11, 12 and 13 (Schedule 2 of the Competition and Consumer Act 2010 (Cth)), the CDR Rules (including section 56), and the Privacy Act 1988 (Cth).</p>', '2027-05-01', 'compliance', 'draft', '69f970995eaf8b697748c2af', '2026-05-05T04:22:49.710000', '2026-05-05T04:45:25.247000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Security Operations', 'CISO', NULL, 'POL-014', '["ISO27001","SOC2","CDR"]', 'Establishes log generation, retention, protection and monitoring requirements.', 'Logging and Monitoring Policy', NULL, '1.0', '<h1>Logging and Monitoring Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Security Operations &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the requirements for the generation, collection, retention, protection, monitoring and review of security-relevant log data. Effective logging and monitoring underpin detection, response and forensic investigation, and support ISO/IEC 27001 Annex A.8.15–A.8.17, SOC 2 CC7.2–CC7.4 and CDR Privacy Safeguard 12.</p><h2>2. Scope</h2><p>This policy applies to all systems, applications, infrastructure, network devices, identity systems, security tooling and third-party services that support the organisation''s operations or process Confidential or Restricted data – including the CDR data environment.</p><h2>3. Log Generation Requirements</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Category</th><th>Required Events</th></tr><tr><td>Authentication</td><td>Successful and failed sign-ins, MFA challenges, account lockouts, session creation/termination</td></tr><tr><td>Authorisation</td><td>Privilege elevation, role/permission changes, denied access</td></tr><tr><td>Administrative</td><td>Configuration changes, account creation/modification/deletion, key/secret operations</td></tr><tr><td>Data Access</td><td>Read/write/delete of Restricted data (incl. CDR/PII), bulk export, schema changes</td></tr><tr><td>Application</td><td>Critical errors, security exceptions, integration failures, anomalous business events</td></tr><tr><td>Network / Infrastructure</td><td>Firewall denies, IDS/IPS alerts, VPN/ZTNA sessions, DNS anomalies</td></tr><tr><td>Security Tooling</td><td>EDR detections, SIEM rule fires, DLP events, vulnerability scan results</td></tr></table><h2>4. Log Quality and Time</h2><ul><li>Logs shall include accurate, synchronised UTC timestamps (NTP);</li><li>Each event shall include sufficient context (actor, action, target, source, outcome);</li><li>Sensitive payloads (passwords, secrets, full PII/CDR data) shall not be logged.</li></ul><h2>5. Centralisation and Protection</h2><ul><li>Logs shall be forwarded to the centralised SIEM in near-real-time;</li><li>Log storage shall be append-only, access-controlled and tamper-evident;</li><li>Access to log management shall be MFA-enforced, least-privilege, and reviewed quarterly;</li><li>Modifications to log configuration shall themselves be logged.</li></ul><h2>6. Retention</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Log Type</th><th>Online Hot</th><th>Cold / Archive</th></tr><tr><td>Authentication / Authorisation</td><td>12 months</td><td>+ 12 months</td></tr><tr><td>Administrative / Privileged</td><td>12 months</td><td>+ 24 months</td></tr><tr><td>Data Access (CDR/PII)</td><td>12 months</td><td>+ 24 months (or longer per regulator)</td></tr><tr><td>Network / Infrastructure</td><td>6 months</td><td>+ 6 months</td></tr></table><h2>7. Monitoring and Detection</h2><ul><li>The SIEM shall implement use cases mapped to MITRE ATT&amp;CK and aligned to organisational threat model;</li><li>24x7 monitoring shall be in place for High and Critical alerts (in-house or via MDR);</li><li>Alert tuning shall be performed continuously to maintain quality and reduce noise;</li><li>Detection coverage gaps shall be tracked as control deficiencies.</li></ul><h2>8. Review and Reporting</h2><ul><li>High-risk events (privileged access, off-hours admin, mass data access) shall be reviewed at least weekly;</li><li>Logging coverage health (sources reporting, ingestion volume, gaps) shall be reviewed monthly;</li><li>Logging and monitoring metrics shall be reported to the Security Steering Committee quarterly.</li></ul><h2>9. Privacy and Legal Considerations</h2><p>Logging shall be designed to meet privacy principles – collected for a defined purpose, minimal data, retained only as long as necessary. Personal information in logs shall be pseudonymised where feasible. Workforce monitoring shall be in line with applicable law and the Acceptable Use Policy.</p><h2>10. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Security Operations</td><td>Owns SIEM, detection content and 24x7 monitoring</td></tr><tr><td>CISO</td><td>Approves logging standard and exceptions</td></tr><tr><td>Service Owners</td><td>Onboard owned systems to SIEM with required events</td></tr><tr><td>Engineering / IT</td><td>Implement application and infrastructure logging</td></tr><tr><td>Privacy / DPO</td><td>Review logging of personal information</td></tr></table><h2>11. Compliance</h2><p>Disabling, tampering with, or bypassing logging is prohibited and shall be treated as a security incident. Gaps in coverage shall be remediated through the corrective action process.</p><h2>12. Policy Review</h2><p>This policy shall be reviewed at least annually and on material technology or threat-landscape change.</p><h2>13. Related Controls</h2><p>This policy supports ISO/IEC 27001:2022 Annex A.8.15, A.8.16, A.8.17; SOC 2 CC7.2–CC7.4; and CDR Privacy Safeguard 12 (Schedule 2 Part 1).</p>', '2027-05-01', 'operations_security', 'draft', '69f970995eaf8b697748c2b0', '2026-05-05T04:22:49.710000', '2026-05-05T04:45:25.260000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, '<h1>Information Security Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This Information Security Policy establishes the organisation''s commitment to protecting the confidentiality, integrity, and availability of all information assets. It provides the overarching framework for all information security activities and is supported by a suite of topic-specific policies and procedures.</p><h2>2. Scope</h2><p>This policy applies to all employees, contractors, consultants, temporary workers, and any other persons who have access to the organisation''s information assets, systems, and facilities, regardless of location. It covers all information assets including digital data, physical documents, software, hardware, networks, and cloud services.</p><h2>3. Policy Statement</h2><p>The organisation is committed to:</p><ul><li>Protecting information from unauthorised access, use, disclosure, disruption, modification, or destruction;</li><li>Ensuring the confidentiality, integrity, and availability of information in accordance with business requirements and applicable legal and regulatory obligations;</li><li>Meeting applicable contractual, regulatory, and legal requirements related to information security;</li><li>Maintaining an effective Information Security Management System (ISMS) in alignment with ISO/IEC 27001;</li><li>Ensuring security controls are commensurate with the risks identified through formal risk assessment;</li><li>Promoting a culture of security awareness across the organisation.</li></ul><h2>4. Information Security Objectives</h2><p>The organisation shall establish, maintain, and review information security objectives aligned with this policy. Objectives shall be measurable where practicable and communicated to relevant personnel. Current objectives include:</p><ul><li>Achieve and maintain ISO 27001 certification;</li><li>Obtain a clean SOC 2 Type II assurance report;</li><li>Complete ASAE 3150 assurance engagement with no qualified opinion;</li><li>Achieve zero critical unpatched vulnerabilities within SLA timeframes;</li><li>Maintain security awareness training completion rate above 95%.</li></ul><h2>5. Roles and Responsibilities</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Board of Directors</td><td>Oversight and approval of information security strategy and risk appetite</td></tr><tr><td>CEO</td><td>Executive accountability for information security; approval of this policy</td></tr><tr><td>CISO</td><td>Ownership, maintenance, and implementation of the ISMS; reporting to executive on security posture</td></tr><tr><td>All Staff</td><td>Compliance with this policy and all supporting policies; reporting of security incidents</td></tr><tr><td>IT / DevOps</td><td>Implementation and maintenance of technical security controls</td></tr><tr><td>HR</td><td>Integration of security requirements into employment lifecycle</td></tr></table><h2>6. Risk Management</h2><p>The organisation shall conduct formal information security risk assessments at least annually and whenever significant changes occur. Risks shall be assessed using the organisation''s risk assessment methodology and treated in accordance with the risk treatment plan. Risk acceptance decisions shall be documented and approved by appropriate management.</p><h2>7. Compliance</h2><p>All personnel must comply with this policy and all supporting information security policies and procedures. Non-compliance may result in disciplinary action, up to and including termination of employment or contract. Suspected non-compliance shall be reported to the CISO.</p><h2>8. Policy Review</h2><p>This policy shall be reviewed at least annually by the CISO and approved by the CEO. It shall also be reviewed following any significant incident, material change to the organisation, or change in applicable legal or regulatory requirements.</p><h2>9. Related Documents</h2><ul><li>Access Control Policy</li><li>Data Classification and Handling Policy</li><li>Incident Response Plan</li><li>Business Continuity Plan</li><li>Risk Management Policy</li><li>Acceptable Use Policy</li><li>Change Management Policy</li><li>Vendor Management Policy</li><li>HR Security Policy</li><li>Physical Security Policy</li><li>Cryptography Policy</li></ul>', '2027-05-01', '["SOC2","ASAE3150","ISO27001"]', 'Overarching policy defining the organisation''s approach to information security management.', 'Information Security Policy', 'information_security', NULL, '1.0', 'draft', 'POL-001', '69f93e5390ec2a0b8fa44141', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:15.904000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, '<h1>Access Control Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes requirements for controlling access to the organisation''s information systems, applications, and data. It ensures that access is granted on a need-to-know, least-privilege basis and that access rights are managed throughout the user lifecycle.</p><h2>2. Scope</h2><p>This policy applies to all information systems, applications, databases, cloud services, and network infrastructure owned or operated by the organisation. It applies to all users including employees, contractors, service accounts, and privileged users.</p><h2>3. Access Control Principles</h2><ul><li><strong>Least Privilege:</strong> Users shall be granted the minimum level of access required to perform their duties.</li><li><strong>Need to Know:</strong> Access to sensitive information shall be restricted to those with a legitimate business requirement.</li><li><strong>Separation of Duties:</strong> Conflicting roles and responsibilities shall be separated to prevent fraud and error.</li><li><strong>Default Deny:</strong> Access shall be denied unless explicitly granted.</li></ul><h2>4. User Access Management</h2><h3>4.1 User Registration</h3><p>All access requests must be submitted via the formal access request process and approved by the relevant data owner or manager before access is provisioned. User accounts shall be uniquely identified and must not be shared.</p><h3>4.2 Privileged Access</h3><p>Privileged access (administrative accounts) shall be strictly controlled. Privileged accounts shall only be used for activities requiring elevated permissions. All privileged access shall be managed via the organisation''s Privileged Access Management (PAM) solution with session recording enabled.</p><h3>4.3 Access Reviews</h3><p>All user access rights shall be reviewed at least quarterly by the relevant system owner or manager. Access that is no longer required shall be removed within five (5) business days of the review decision.</p><h3>4.4 Access Revocation</h3><p>Access to all systems shall be revoked on or before the last day of employment or contract. The HR and IT teams shall follow the offboarding checklist to ensure timely revocation across all systems.</p><h2>5. Authentication Requirements</h2><h3>5.1 Multi-Factor Authentication</h3><p>Multi-factor authentication (MFA) is mandatory for:</p><ul><li>All remote access to internal systems;</li><li>All access to production environments and administrative consoles;</li><li>All access to cloud infrastructure and SaaS applications containing sensitive data;</li><li>All privileged user accounts.</li></ul><h3>5.2 Password Requirements</h3><p>Where passwords are used, they shall meet the following minimum requirements:</p><ul><li>Minimum length of 12 characters;</li><li>Complexity requirements including a mix of character types;</li><li>Passwords shall not be reused for at least 12 generations;</li><li>Accounts shall be locked after 10 consecutive failed login attempts.</li></ul><h2>6. Remote Access</h2><p>Remote access to internal systems shall be conducted via approved VPN or Zero Trust Network Access (ZTNA) solution. MFA is required for all remote access sessions. Remote access shall be logged and monitored.</p><h2>7. Service Accounts</h2><p>Service accounts shall be documented, have strong randomly generated passwords or use certificate-based authentication, and shall be reviewed annually. Service accounts shall be granted only the permissions required for the specific function.</p><h2>8. Third-Party Access</h2><p>Third-party vendors requiring access to systems shall be granted time-limited access only. All third-party access shall be approved by the relevant data owner and monitored for the duration of the access period.</p><h2>9. Related Controls</h2><p>This policy supports SOC 2 criteria CC6.1–CC6.5 and ISO 27001 controls A.8.2, A.8.3, A.8.5.</p>', '2027-05-01', '["SOC2","ISO27001"]', 'Defines requirements for user access management, authentication, and authorisation across all systems.', 'Access Control Policy', 'access_control', NULL, '1.0', 'draft', 'POL-002', '69f93e5390ec2a0b8fa44142', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:16.155000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, 'POL-006', '["SOC2","ISO27001"]', 'Establishes how the organisation classifies, labels, and handles information assets based on sensitivity.', 'Data Classification and Handling Policy', NULL, '1.0', '<h1>Data Classification and Handling Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines how the organisation classifies its information assets and establishes handling requirements appropriate to each classification level. It ensures that sensitive information receives proportionate protection and that all personnel understand their obligations.</p><h2>2. Scope</h2><p>This policy applies to all information created, received, stored, processed, or transmitted by the organisation, regardless of format (digital or physical) or location.</p><h2>3. Classification Levels</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Classification</th><th>Description</th><th>Examples</th></tr><tr><td><strong>Public</strong></td><td>Information approved for unrestricted public disclosure</td><td>Marketing materials, public website content</td></tr><tr><td><strong>Internal</strong></td><td>Information for internal use only; not for external parties without authorisation</td><td>Internal procedures, staff communications</td></tr><tr><td><strong>Confidential</strong></td><td>Sensitive business information; limited distribution on need-to-know basis</td><td>Financial data, contracts, customer data, employee records</td></tr><tr><td><strong>Restricted</strong></td><td>Highly sensitive information; most stringent controls apply</td><td>Authentication credentials, cryptographic keys, audit findings, personal health information</td></tr></table><h2>4. Handling Requirements</h2><h3>4.1 Storage</h3><ul><li><strong>Public:</strong> No special requirements.</li><li><strong>Internal:</strong> Store on authorised systems; access controlled by role.</li><li><strong>Confidential:</strong> Encrypted at rest; access logging enabled.</li><li><strong>Restricted:</strong> Encrypted at rest with AES-256 or equivalent; strict access controls; access reviewed quarterly.</li></ul><h3>4.2 Transmission</h3><ul><li>Confidential and Restricted data must be encrypted in transit using TLS 1.2 or higher.</li><li>Restricted data must not be transmitted via personal email or unapproved file-sharing services.</li></ul><h3>4.3 Retention and Disposal</h3><p>Data shall be retained in accordance with the Data Retention Schedule. When no longer required, data shall be securely deleted (digital) or shredded (physical). Disposal shall be documented.</p><h2>5. Labelling</h2><p>All documents classified as Confidential or Restricted shall be clearly labelled with the classification level in the document header and footer. Electronic files shall be named or tagged to reflect their classification where practicable.</p><h2>6. Responsibilities</h2><p>Data owners are responsible for classifying information under their stewardship. All staff are responsible for handling information according to its classification level.</p><h2>7. Related Controls</h2><p>Supports ISO 27001 A.5.1, SOC 2 CC2.1, CC6.7.</p>', '2027-05-01', 'data_protection', 'draft', '69f93e5390ec2a0b8fa44143', '2026-05-05T00:48:19.070000', '2026-05-05T04:52:05.047000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, '<h1>Incident Response Plan</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This Incident Response Plan (IRP) defines the organisation''s approach to identifying, containing, eradicating, and recovering from information security incidents. It ensures a consistent, effective, and timely response that minimises impact to business operations and meets notification obligations.</p><h2>2. Scope</h2><p>This plan applies to all information security incidents affecting the organisation''s systems, data, personnel, or reputation. It covers incidents involving but not limited to: data breaches, ransomware, unauthorised access, denial of service, insider threats, and physical security events.</p><h2>3. Incident Severity Classification</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Severity</th><th>Description</th><th>Response Time</th></tr><tr><td><strong>P1 – Critical</strong></td><td>Active breach, ransomware, confirmed data loss affecting customers or critical systems down</td><td>Immediate (within 1 hour)</td></tr><tr><td><strong>P2 – High</strong></td><td>Suspected breach, significant system compromise, or material service degradation</td><td>Within 4 hours</td></tr><tr><td><strong>P3 – Medium</strong></td><td>Isolated security event with limited impact; policy violation</td><td>Within 1 business day</td></tr><tr><td><strong>P4 – Low</strong></td><td>Minor event with no immediate impact; informational</td><td>Within 3 business days</td></tr></table><h2>4. Incident Response Phases</h2><h3>4.1 Preparation</h3><p>Maintain and test this plan annually. Ensure Incident Response Team (IRT) members are trained. Maintain contact lists, forensic tools, and communication templates ready for activation.</p><h3>4.2 Identification and Detection</h3><p>Incidents may be detected via: SIEM alerts, user reports, third-party notifications, or external intelligence. All potential incidents must be reported to the CISO immediately via the security incident hotline or ticketing system.</p><h3>4.3 Containment</h3><p>Upon confirmation of an incident, the IRT shall implement short-term containment measures to prevent further damage. This may include isolating affected systems, revoking compromised credentials, blocking malicious IP addresses, or disabling affected accounts.</p><h3>4.4 Eradication</h3><p>The root cause of the incident shall be identified and removed. This may include removing malware, applying patches, closing attack vectors, and resetting compromised credentials.</p><h3>4.5 Recovery</h3><p>Affected systems shall be restored to normal operation using clean backups or rebuilt environments. Systems shall be monitored closely following restoration to confirm normal operation and detect recurrence.</p><h3>4.6 Post-Incident Review</h3><p>A post-incident review (PIR) shall be conducted within 10 business days for all P1 and P2 incidents. The PIR shall document the timeline, impact, root cause, response effectiveness, and lessons learned. Findings shall be actioned and tracked to completion.</p><h2>5. Notification and Communication</h2><h3>5.1 Internal Communication</h3><p>The CISO shall notify executive leadership of all P1 and P2 incidents within two (2) hours of confirmation. Regular status updates shall be provided throughout the incident.</p><h3>5.2 Regulatory and Customer Notification</h3><p>Where a notifiable data breach has occurred under applicable privacy legislation (e.g., Australian Privacy Act – Notifiable Data Breaches scheme), notification shall be made to the relevant regulator within 72 hours and to affected individuals without undue delay. Legal counsel shall be engaged prior to external notifications.</p><h2>6. Incident Response Team</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Role</th><th>Responsibility</th></tr><tr><td>Incident Commander</td><td>CISO – overall incident coordination and decision-making</td></tr><tr><td>Technical Lead</td><td>IT/Security Engineer – technical investigation and remediation</td></tr><tr><td>Communications Lead</td><td>CEO / Legal – internal and external communications</td></tr><tr><td>HR Representative</td><td>HR Manager – employee-related matters</td></tr></table><h2>7. Evidence Preservation</h2><p>All incident evidence shall be preserved in accordance with chain-of-custody procedures. Logs, system images, and artefacts shall not be deleted until the investigation is complete and approved by the CISO.</p><h2>8. Related Controls</h2><p>Supports SOC 2 CC7.3, CC7.4, CC7.5 and ISO 27001 A.5.24–A.5.28.</p>', '2027-05-01', '["SOC2","ASAE3150","ISO27001"]', 'Procedures for detecting, classifying, responding to, and recovering from information security incidents.', 'Incident Response Plan', 'incident_response', NULL, '1.0', 'draft', 'POL-007', '69f93e5390ec2a0b8fa44144', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:40.059000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CTO', 'CEO', NULL, 'POL-008', '["SOC2","ASAE3150","ISO27001"]', 'Ensures the organisation can maintain critical functions and recover systems following a disruptive event.', 'Business Continuity and Disaster Recovery Policy', NULL, '1.0', '<h1>Business Continuity and Disaster Recovery Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CTO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the framework for business continuity planning (BCP) and disaster recovery (DR) to ensure that the organisation can continue critical operations and recover IT systems following a disruptive event.</p><h2>2. Scope</h2><p>This policy applies to all critical business functions, information systems, and supporting infrastructure. It encompasses scenarios including but not limited to: natural disasters, cyberattacks, infrastructure failures, pandemic, and supplier disruption.</p><h2>3. Business Impact Analysis</h2><p>A Business Impact Analysis (BIA) shall be conducted at least annually to identify critical business functions, their dependencies, and the impact of disruption over time. The BIA shall define Recovery Time Objectives (RTOs) and Recovery Point Objectives (RPOs) for all critical systems.</p><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>System Tier</th><th>Description</th><th>RTO</th><th>RPO</th></tr><tr><td>Tier 1 – Mission Critical</td><td>Systems that, if unavailable, immediately halt business operations</td><td>4 hours</td><td>1 hour</td></tr><tr><td>Tier 2 – Business Critical</td><td>Systems important to operations but with some manual workarounds</td><td>24 hours</td><td>4 hours</td></tr><tr><td>Tier 3 – Business Important</td><td>Systems supporting operational efficiency but not immediately critical</td><td>72 hours</td><td>24 hours</td></tr></table><h2>4. Backup Requirements</h2><ul><li>All Tier 1 and Tier 2 systems must have automated daily backups;</li><li>Backups must be stored in a geographically separate location or cloud region;</li><li>Backup integrity must be tested monthly via restore verification;</li><li>Immutable (WORM) backups must be implemented for critical data to protect against ransomware;</li><li>Backup access shall be restricted and monitored.</li></ul><h2>5. Disaster Recovery</h2><p>A Disaster Recovery Plan (DRP) shall be maintained for all Tier 1 systems documenting step-by-step recovery procedures. The DRP shall be tested at least annually via a full failover exercise and the results documented. Deficiencies shall be remediated within 90 days.</p><h2>6. Business Continuity Plan</h2><p>The Business Continuity Plan shall document procedures for maintaining critical business functions during a disruption, including manual workarounds, alternative work locations, communication procedures, and escalation chains. The BCP shall be reviewed annually and following any significant incident.</p><h2>7. Testing and Maintenance</h2><p>BCP and DRP exercises shall be conducted at least annually. Tests may include tabletop exercises, functional tests, or full failover simulations. Test results shall be reported to executive leadership and the board.</p><h2>8. Related Controls</h2><p>Supports SOC 2 A1.2, A1.3 and ISO 27001 A.5.29, A.5.30.</p>', '2027-05-01', 'business_continuity', 'draft', '69f93e5390ec2a0b8fa44145', '2026-05-05T00:48:19.070000', '2026-05-05T04:52:05.270000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CTO', 'CEO', NULL, 'POL-009', '["SOC2","ISO27001"]', 'Controls for managing changes to IT systems, applications, and infrastructure to prevent unauthorised or untested changes.', 'Change Management Policy', NULL, '1.0', '<h1>Change Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CTO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes controls for managing changes to the organisation''s information systems, applications, and infrastructure. It ensures that all changes are authorised, tested, and documented to minimise the risk of service disruption, security vulnerabilities, or non-compliance.</p><h2>2. Scope</h2><p>This policy applies to all changes to production systems, applications, infrastructure, network components, databases, and cloud services. It applies to all personnel involved in the delivery, approval, or implementation of changes.</p><h2>3. Change Types</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Change Type</th><th>Description</th><th>Approval Required</th></tr><tr><td>Standard</td><td>Pre-approved, low-risk, well-understood changes with defined procedures</td><td>Pre-approved; log only</td></tr><tr><td>Normal</td><td>Planned changes requiring risk assessment and approval before implementation</td><td>Change Advisory Board (CAB)</td></tr><tr><td>Emergency</td><td>Urgent changes required to restore service or remediate a critical security vulnerability</td><td>CISO or CTO + retrospective CAB review</td></tr></table><h2>4. Change Process</h2><h3>4.1 Request</h3><p>All changes must be submitted via the change management system with a description, business justification, risk assessment, test plan, rollback plan, and implementation timeline.</p><h3>4.2 Assessment and Approval</h3><p>Normal changes must be reviewed by the Change Advisory Board (CAB) and approved before implementation. The CAB shall meet at least weekly. Changes with significant security implications must be approved by the CISO.</p><h3>4.3 Testing</h3><p>All changes must be tested in a non-production environment before deployment to production. Security testing (including vulnerability scanning) must be performed for changes affecting security-relevant components.</p><h3>4.4 Implementation</h3><p>Changes shall be implemented during approved maintenance windows unless classified as emergency. All implementation steps shall be documented. Changes must include a verified rollback plan.</p><h3>4.5 Post-Implementation Review</h3><p>All normal and emergency changes shall be reviewed within five (5) business days of implementation to confirm success and identify any issues.</p><h2>5. Emergency Changes</h2><p>Emergency changes may bypass the standard approval process to address critical incidents. However, they must be approved by at least two authorised managers (CISO or CTO) and submitted for retrospective CAB review within two (2) business days.</p><h2>6. Segregation of Duties</h2><p>No individual shall both request and approve their own change. Development staff shall not deploy directly to production environments without an independent approval step.</p><h2>7. Related Controls</h2><p>Supports SOC 2 CC8.1, CC6.8 and ISO 27001 A.8.32.</p>', '2027-05-01', 'change_management', 'draft', '69f93e5390ec2a0b8fa44146', '2026-05-05T00:48:19.070000', '2026-05-05T04:52:05.506000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Compliance Manager', 'CEO', NULL, '<h1>Vendor and Third-Party Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Compliance Manager &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the requirements for managing information security risks associated with third-party vendors, suppliers, and subservice organisations that access, process, store, or transmit the organisation''s information or systems.</p><h2>2. Scope</h2><p>This policy applies to all third-party relationships where the vendor has access to the organisation''s information assets, systems, or premises. It applies to all vendor types including cloud service providers, IT service providers, professional services firms, and subservice organisations relied upon for SOC 2 / ASAE 3150 in-scope services.</p><h2>3. Vendor Classification</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Tier</th><th>Description</th><th>Assessment Frequency</th></tr><tr><td>Tier 1 – Critical</td><td>Vendors with access to sensitive or personal data, or those providing critical services</td><td>Annual full assessment</td></tr><tr><td>Tier 2 – High</td><td>Vendors with limited data access or providing important (non-critical) services</td><td>Annual questionnaire + review of certifications</td></tr><tr><td>Tier 3 – Standard</td><td>Vendors with no data access or providing commoditised services</td><td>Biennial review; certification review only</td></tr></table><h2>4. Vendor Onboarding</h2><p>Before engaging a Tier 1 or Tier 2 vendor, the following must be completed:</p><ul><li>Completion of the organisation''s vendor security questionnaire;</li><li>Review of the vendor''s security certifications (ISO 27001, SOC 2, etc.);</li><li>Risk assessment by the CISO;</li><li>Execution of a Data Processing Agreement (DPA) where personal data is involved;</li><li>Inclusion of information security obligations in the contract;</li><li>Right-to-audit clause included for Tier 1 vendors.</li></ul><h2>5. Ongoing Monitoring</h2><p>Vendor security posture shall be monitored on an ongoing basis. Tier 1 vendors shall be reviewed annually. The organisation shall request updated SOC 2 reports, ISO 27001 certificates, or equivalent attestations each year. Material changes to vendor security posture or ownership shall trigger an out-of-cycle review.</p><h2>6. Subservice Organisations (ASAE 3150)</h2><p>For the purposes of the ASAE 3150 engagement, subservice organisations that are relevant to the in-scope services shall be identified and disclosed in the system description. The organisation shall monitor the controls of subservice organisations by reviewing their SOC 2 or equivalent assurance reports annually and documenting complementary controls it has implemented.</p><h2>7. Vendor Offboarding</h2><p>Upon termination of a vendor relationship, all access to the organisation''s systems and data shall be revoked immediately. The vendor shall certify destruction or return of all organisational data. Shared credentials shall be rotated.</p><h2>8. Related Controls</h2><p>Supports SOC 2 CC9.2 and ISO 27001 A.5.19–A.5.22.</p>', '2027-05-01', '["SOC2","ASAE3150","ISO27001"]', 'Requirements for assessing, onboarding, monitoring, and offboarding third-party vendors with access to information or systems.', 'Vendor and Third-Party Management Policy', 'vendor_management', NULL, '1.0', 'draft', 'POL-010', '69f93e5390ec2a0b8fa44147', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:40.097000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, 'POL-011', '["SOC2","ISO27001"]', 'Defines acceptable use of the organisation''s IT resources, systems, and data by all users.', 'Acceptable Use Policy', NULL, '1.0', '<h1>Acceptable Use Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines the acceptable use of the organisation''s IT resources, systems, networks, and data. It protects the organisation''s assets from misuse, legal liability, and security risks.</p><h2>2. Scope</h2><p>This policy applies to all employees, contractors, and third parties using the organisation''s IT resources, including computers, mobile devices, email, internet, cloud services, and internal systems.</p><h2>3. Acceptable Use</h2><p>Users may use organisational IT resources for:</p><ul><li>Performing their assigned job duties;</li><li>Reasonable incidental personal use that does not interfere with work performance or consume excessive resources;</li><li>Accessing systems and data for which they have been authorised.</li></ul><h2>4. Prohibited Activities</h2><p>The following activities are strictly prohibited:</p><ul><li>Accessing, downloading, storing, or distributing illegal, offensive, or discriminatory content;</li><li>Using organisational systems for commercial activities unrelated to work;</li><li>Attempting to circumvent security controls, access unauthorised systems, or exploit vulnerabilities;</li><li>Sharing login credentials or allowing others to use your account;</li><li>Installing unauthorised software on organisational devices;</li><li>Transmitting confidential data via unapproved channels (e.g., personal email, consumer file sharing);</li><li>Mining cryptocurrency or performing activities that consume excessive computational resources;</li><li>Using organisational resources to harass, defame, or discriminate against others.</li></ul><h2>5. Monitoring</h2><p>The organisation reserves the right to monitor the use of its IT resources in accordance with applicable law and privacy regulations. Users have no expectation of privacy when using organisational systems. Monitoring may include logging of internet activity, email scanning, and endpoint monitoring.</p><h2>6. Personal Devices (BYOD)</h2><p>Employees using personal devices to access organisational systems must comply with the organisation''s Mobile Device Policy, which includes enrolling the device in the Mobile Device Management (MDM) solution and maintaining up-to-date operating system and security patches.</p><h2>7. Consequences of Non-Compliance</h2><p>Violations of this policy may result in disciplinary action up to and including termination of employment or contract, and may be referred to law enforcement authorities where illegal activity is suspected.</p><h2>8. Related Controls</h2><p>Supports ISO 27001 A.5.10 and SOC 2 CC1.1.</p>', '2027-05-01', 'acceptable_use', 'draft', '69f93e5390ec2a0b8fa44148', '2026-05-05T00:48:19.070000', '2026-05-05T04:52:04.818000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('HR Manager', 'CEO', NULL, '<h1>HR Security Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> HR Manager &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines information security requirements applicable throughout the employment and contractor lifecycle to reduce the risk of human-related security incidents, including insider threats, data mishandling, and social engineering.</p><h2>2. Scope</h2><p>This policy applies to all permanent employees, temporary workers, contractors, and interns engaged by the organisation.</p><h2>3. Pre-Employment Screening</h2><p>Prior to commencing employment or a contractor engagement, the organisation shall conduct background verification checks appropriate to the role. For roles with access to sensitive data or systems, checks shall include:</p><ul><li>Identity verification;</li><li>Employment history verification (past 5 years);</li><li>Criminal record check (where legally permissible);</li><li>Reference checks (minimum two).</li></ul><p>All background checks shall be conducted by an approved third-party screening provider and results documented in the HR system.</p><h2>4. Terms and Conditions of Employment</h2><p>All employees and contractors shall sign an employment contract or engagement agreement prior to commencing work. Contracts shall include:</p><ul><li>Obligations to comply with the organisation''s information security policies;</li><li>Confidentiality obligations;</li><li>Obligations regarding intellectual property;</li><li>Acknowledgement that systems may be monitored.</li></ul><h2>5. Security Awareness and Training</h2><p>All staff shall complete mandatory information security awareness training:</p><ul><li>Within 30 days of commencement (onboarding training);</li><li>Annually thereafter (refresher training);</li><li>Role-specific training for high-risk roles (e.g., administrators, developers, finance staff).</li></ul><p>Training completion shall be tracked and reported to the CISO quarterly. Staff who fail to complete training within the required timeframe shall have access suspended pending completion.</p><h2>6. Disciplinary Process</h2><p>Violations of information security policies shall be handled through the organisation''s disciplinary process. Disciplinary action shall be proportionate to the severity of the breach. Serious breaches (e.g., deliberate data theft) may result in immediate termination and referral to law enforcement.</p><h2>7. Offboarding</h2><p>Upon termination or resignation, the following steps shall be completed on or before the final day:</p><ul><li>All system access revoked;</li><li>Company devices returned and wiped;</li><li>Ongoing confidentiality obligations confirmed in writing;</li><li>Exit interview completed.</li></ul><h2>8. Related Controls</h2><p>Supports ISO 27001 A.6.1–A.6.6 and SOC 2 CC1.4.</p>', '2027-05-01', '["ISO27001"]', 'Defines security requirements throughout the employee and contractor lifecycle including screening, training, and offboarding.', 'HR Security Policy', 'hr_security', NULL, '1.0', 'draft', 'POL-012', '69f93e5390ec2a0b8fa44149', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:40.121000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('Facilities Manager', 'CEO', NULL, '<h1>Physical and Environmental Security Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> Facilities Manager &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes requirements for protecting the organisation''s physical premises, server rooms, equipment, and environmental systems from unauthorised access, damage, or disruption.</p><h2>2. Scope</h2><p>This policy applies to all organisational premises, data centres, server rooms, and equipment including offices, remote working facilities, and cloud provider data centres (addressed via third-party attestations).</p><h2>3. Physical Security Perimeters</h2><p>Security perimeters shall be defined for all locations containing sensitive information or information processing facilities. Entry to these areas shall be controlled using electronic access controls (badge readers, PIN pads, or biometrics). Perimeters shall be clearly demarcated.</p><h2>4. Access Controls</h2><ul><li>Access to server rooms and sensitive areas shall be restricted to authorised personnel only;</li><li>Visitor access shall be logged, escorted, and limited to areas required for the visit;</li><li>Access rights shall be reviewed quarterly and revoked promptly when no longer required;</li><li>Tailgating and piggybacking are strictly prohibited.</li></ul><h2>5. Physical Security Monitoring</h2><ul><li>CCTV shall be installed at all entry and exit points and in server rooms;</li><li>CCTV footage shall be retained for a minimum of 90 days;</li><li>Alarm systems shall be maintained in operational condition and tested regularly.</li></ul><h2>6. Equipment Security</h2><ul><li>All portable devices containing sensitive data must be encrypted;</li><li>Equipment shall not be removed from the premises without prior authorisation;</li><li>Unattended equipment must be locked or powered off;</li><li>Clean desk and clear screen policies shall be enforced.</li></ul><h2>7. Environmental Controls</h2><p>Server rooms shall maintain appropriate environmental controls including:</p><ul><li>Temperature and humidity monitoring with alerting;</li><li>Uninterruptible Power Supply (UPS) for critical systems;</li><li>Fire suppression systems;</li><li>Water leak detection.</li></ul><h2>8. Equipment Disposal</h2><p>All equipment being decommissioned or disposed of shall have data securely wiped using NIST 800-88 compliant methods or physically destroyed. Disposal shall be documented and certificates of destruction obtained from third-party disposal providers.</p><h2>9. Related Controls</h2><p>Supports ISO 27001 A.7.1–A.7.13 and SOC 2 CC6.4.</p>', '2027-05-01', '["ISO27001","SOC2"]', 'Controls for protecting physical premises, equipment, and environmental systems from unauthorised access or damage.', 'Physical and Environmental Security Policy', 'physical_security', NULL, '1.0', 'draft', 'POL-013', '69f93e5390ec2a0b8fa4414a', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:40.132000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, 'POL-014', '["SOC2","ASAE3150","ISO27001"]', 'Framework for identifying, assessing, treating, and monitoring information security risks across the organisation.', 'Risk Management Policy', NULL, '1.0', '<h1>Risk Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the organisation''s framework for identifying, assessing, treating, and monitoring information security risks. It ensures that risks are managed systematically and in accordance with the organisation''s risk appetite.</p><h2>2. Scope</h2><p>This policy applies to all information security risks across the organisation''s systems, processes, people, and third-party relationships.</p><h2>3. Risk Appetite</h2><p>The organisation has a <strong>low risk appetite</strong> for information security risks that could result in:</p><ul><li>Unauthorised disclosure of personal or customer data;</li><li>Loss of availability of critical systems beyond agreed RTO;</li><li>Regulatory non-compliance or enforcement action;</li><li>Reputational damage affecting customer trust.</li></ul><h2>4. Risk Assessment Methodology</h2><p>Risks shall be assessed using a 5x5 likelihood-impact matrix. Scores are calculated as: <strong>Risk Score = Likelihood (1–5) × Impact (1–5)</strong>.</p><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Score</th><th>Rating</th><th>Action Required</th></tr><tr><td>20–25</td><td>Critical</td><td>Immediate treatment required; escalate to Board</td></tr><tr><td>12–19</td><td>High</td><td>Treatment plan required within 30 days; executive notification</td></tr><tr><td>6–11</td><td>Medium</td><td>Treatment plan required within 90 days</td></tr><tr><td>1–5</td><td>Low</td><td>Monitor; accept or treat as resources allow</td></tr></table><h2>5. Risk Treatment Options</h2><ul><li><strong>Mitigate:</strong> Implement controls to reduce likelihood or impact;</li><li><strong>Accept:</strong> Acknowledge and accept the risk within appetite (requires CISO and executive approval for medium+ risks);</li><li><strong>Transfer:</strong> Transfer the risk via insurance, contracts, or outsourcing;</li><li><strong>Avoid:</strong> Discontinue the activity that gives rise to the risk.</li></ul><h2>6. Risk Register</h2><p>A formal risk register shall be maintained and reviewed quarterly by the CISO. The register shall document: risk description, owner, likelihood, impact, risk score, current controls, treatment option, treatment plan, target date, and residual risk score.</p><h2>7. Risk Review</h2><p>The full risk assessment shall be conducted at least annually and following significant changes including new systems, major incidents, or changes in the threat landscape. Risk treatment effectiveness shall be reviewed as part of the annual ISMS management review.</p><h2>8. Related Controls</h2><p>Supports SOC 2 CC3.1–CC3.4, CC9.1 and ISO 27001 Clause 6.1.</p>', '2027-05-01', 'risk_management', 'draft', '69f93e5390ec2a0b8fa4414b', '2026-05-05T00:48:19.070000', '2026-05-05T04:52:04.563000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_id", "frameworks", "description", "title", "approved_date", "version", "policy_content", "review_date", "category", "status", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, 'POL-003', '["ISO27001","SOC2"]', 'Defines requirements for the use of cryptographic controls and the management of cryptographic keys.', 'Cryptography and Key Management Policy', NULL, '1.0', '<h1>Cryptography and Key Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy defines the organisation''s requirements for the use of cryptographic controls to protect information confidentiality, integrity, and authenticity. It establishes standards for cryptographic algorithms, key management, and the lifecycle of cryptographic materials.</p><h2>2. Scope</h2><p>This policy applies to all cryptographic implementations including data encryption, digital signatures, certificate management, and secure communications across all systems and applications.</p><h2>3. Approved Cryptographic Standards</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>Use Case</th><th>Approved Algorithm / Protocol</th><th>Minimum Key Length</th></tr><tr><td>Symmetric encryption (data at rest)</td><td>AES-GCM</td><td>256-bit</td></tr><tr><td>Asymmetric encryption / key exchange</td><td>RSA, ECDH</td><td>RSA: 2048-bit; ECDH: P-256 or higher</td></tr><tr><td>Digital signatures</td><td>RSA-PSS, ECDSA</td><td>RSA: 2048-bit; ECDSA: P-256</td></tr><tr><td>Hashing</td><td>SHA-256, SHA-384, SHA-512</td><td>N/A</td></tr><tr><td>Transport encryption</td><td>TLS 1.2, TLS 1.3</td><td>N/A</td></tr><tr><td>Password hashing</td><td>Argon2id, bcrypt, scrypt</td><td>Work factor per current OWASP guidance</td></tr></table><h3>Prohibited Algorithms</h3><p>The following algorithms are prohibited due to known weaknesses: DES, 3DES, RC4, MD5, SHA-1, SSL 2.0/3.0, TLS 1.0/1.1.</p><h2>4. Key Management</h2><h3>4.1 Key Generation</h3><p>Cryptographic keys shall be generated using a cryptographically secure random number generator (CSPRNG). Key generation shall occur in a trusted, controlled environment.</p><h3>4.2 Key Storage</h3><p>Private keys and symmetric keys shall be stored securely using a Hardware Security Module (HSM) or an approved Key Management Service (KMS) such as AWS KMS, Azure Key Vault, or GCP Cloud KMS. Keys shall never be stored in plaintext on disk or in source code.</p><h3>4.3 Key Rotation</h3><ul><li>TLS certificates: renewed before expiry (minimum 30 days prior);</li><li>Data encryption keys: rotated at least annually;</li><li>API keys and secrets: rotated at least every 90 days or upon suspected compromise.</li></ul><h3>4.4 Key Revocation and Destruction</h3><p>Compromised or no longer required keys shall be revoked and securely destroyed immediately. Destruction shall be documented.</p><h2>5. Certificate Management</h2><p>A certificate inventory shall be maintained documenting all TLS/SSL certificates including expiry dates. Automated certificate monitoring and renewal shall be implemented where possible. Certificates shall only be issued by trusted Certificate Authorities (CAs).</p><h2>6. Related Controls</h2><p>Supports ISO 27001 A.8.24 and SOC 2 CC6.7.</p>', '2027-05-01', 'cryptography', 'draft', '69f93e5390ec2a0b8fa4414c', '2026-05-05T00:48:19.070000', '2026-05-05T04:52:05.716000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_id" = EXCLUDED."policy_id", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "category" = EXCLUDED."category", "status" = EXCLUDED."status", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CISO', 'CEO', NULL, '<h1>Vulnerability Management Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CISO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes the organisation''s requirements for identifying, prioritising, remediating, and monitoring technical vulnerabilities across all information systems and applications.</p><h2>2. Scope</h2><p>This policy applies to all systems within the organisation''s information security boundary including servers, workstations, network devices, applications, cloud infrastructure, and mobile devices.</p><h2>3. Vulnerability Scanning</h2><ul><li>Automated vulnerability scans shall be conducted at least weekly against all internet-facing systems and at least monthly against internal systems;</li><li>Application security testing (SAST, DAST) shall be integrated into the CI/CD pipeline;</li><li>An authenticated scan shall be used where technically feasible to detect patch status and configuration issues.</li></ul><h2>4. Patch and Remediation SLAs</h2><table border=''1'' cellpadding=''6'' cellspacing=''0'' style=''border-collapse:collapse;width:100%''><tr><th>CVSS Severity</th><th>Rating</th><th>Remediation SLA</th></tr><tr><td>9.0–10.0</td><td>Critical</td><td>24 hours (or immediate compensating control)</td></tr><tr><td>7.0–8.9</td><td>High</td><td>7 calendar days</td></tr><tr><td>4.0–6.9</td><td>Medium</td><td>30 calendar days</td></tr><tr><td>0.1–3.9</td><td>Low</td><td>90 calendar days or risk accepted</td></tr></table><h2>5. Penetration Testing</h2><p>External penetration testing shall be conducted by an accredited third-party firm at least annually covering external network, web applications, and where applicable, internal network and social engineering. Findings shall be remediated in accordance with the SLAs above. Test reports shall be retained for three (3) years.</p><h2>6. Exception Management</h2><p>Where a vulnerability cannot be remediated within the defined SLA (e.g., due to business impact of the patch), a formal exception shall be documented including: the vulnerability, reason for exception, compensating controls implemented, residual risk, and risk acceptance by the CISO. Exceptions shall be reviewed monthly.</p><h2>7. Asset Coverage</h2><p>An asset inventory shall be maintained to ensure complete vulnerability scan coverage. Newly deployed systems shall be included in scanning within 24 hours of deployment to production.</p><h2>8. Related Controls</h2><p>Supports ISO 27001 A.8.8 and SOC 2 CC7.1, CC7.2.</p>', '2027-05-01', '["ISO27001","SOC2"]', 'Establishes requirements for identifying, assessing, and remediating technical vulnerabilities in systems and applications.', 'Vulnerability Management Policy', 'operations_security', NULL, '1.0', 'draft', 'POL-004', '69f93e5390ec2a0b8fa4414d', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:16.809000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
INSERT INTO "policy" ("owner", "approver", "file_url", "policy_content", "review_date", "frameworks", "description", "title", "category", "approved_date", "version", "status", "policy_id", "id", "created_date", "updated_date", "created_by_id", "created_by", "is_sample") VALUES ('CTO', 'CEO', NULL, '<h1>Secure Development Lifecycle (SDLC) Policy</h1><p><strong>Version:</strong> 1.0 &nbsp;|&nbsp; <strong>Status:</strong> Draft &nbsp;|&nbsp; <strong>Owner:</strong> CTO &nbsp;|&nbsp; <strong>Review Date:</strong> May 2027</p><h2>1. Purpose</h2><p>This policy establishes requirements for integrating security into every phase of the organisation''s software development lifecycle. It ensures that security is a foundational element of all software and systems developed, acquired, or maintained by the organisation.</p><h2>2. Scope</h2><p>This policy applies to all software development activities including internal development, custom application development, API development, and configuration of commercial off-the-shelf (COTS) software.</p><h2>3. Security Requirements</h2><p>Security requirements shall be defined at the outset of all development projects and include:</p><ul><li>Authentication and authorisation requirements;</li><li>Data protection requirements based on data classification;</li><li>Input validation and output encoding requirements;</li><li>Logging and audit trail requirements;</li><li>Compliance requirements (privacy, regulatory).</li></ul><h2>4. Secure Design</h2><p>Applications shall be designed following security-by-design principles:</p><ul><li>Threat modelling shall be conducted for all new applications and significant changes;</li><li>Security architecture reviews shall be conducted before development commences;</li><li>OWASP Top 10 risks shall be explicitly addressed in application design.</li></ul><h2>5. Secure Coding Standards</h2><p>All developers shall follow the organisation''s secure coding guidelines which include:</p><ul><li>Input validation and parameterised queries to prevent injection attacks;</li><li>Output encoding to prevent XSS;</li><li>Use of approved cryptographic libraries only;</li><li>Secure management of secrets (no hard-coded credentials);</li><li>Error handling that does not expose sensitive information.</li></ul><h2>6. Security Testing in CI/CD</h2><ul><li><strong>SAST (Static Application Security Testing):</strong> Integrated into the CI pipeline; builds fail on critical or high findings;</li><li><strong>SCA (Software Composition Analysis):</strong> Dependency vulnerability scanning on every build;</li><li><strong>DAST (Dynamic Application Security Testing):</strong> Run against staging environment before production deployment;</li><li><strong>Secrets Scanning:</strong> Automated scanning to detect credentials committed to source code.</li></ul><h2>7. Code Review</h2><p>All code changes must be reviewed by at least one other developer before merging to main/production branches. Security-sensitive changes (authentication, authorisation, cryptography) require review by a senior developer or the security team.</p><h2>8. Environment Separation</h2><p>Development, testing, staging, and production environments shall be strictly separated. Production data shall not be used in non-production environments. Access to production environments shall be restricted to authorised personnel.</p><h2>9. Related Controls</h2><p>Supports ISO 27001 A.8.25–A.8.29 and SOC 2 CC8.1.</p>', '2027-05-01', '["ISO27001","SOC2"]', 'Integrates security into the software development process from design through deployment and maintenance.', 'Secure Development Lifecycle (SDLC) Policy', 'operations_security', NULL, '1.0', 'draft', 'POL-005', '69f93e5390ec2a0b8fa4414e', '2026-05-05T00:48:19.070000', '2026-05-05T01:48:17.087000', '69f9384b17e5612680060cd2', 'bfma.www@gmail.com', false) ON CONFLICT (id) DO UPDATE SET "owner" = EXCLUDED."owner", "approver" = EXCLUDED."approver", "file_url" = EXCLUDED."file_url", "policy_content" = EXCLUDED."policy_content", "review_date" = EXCLUDED."review_date", "frameworks" = EXCLUDED."frameworks", "description" = EXCLUDED."description", "title" = EXCLUDED."title", "category" = EXCLUDED."category", "approved_date" = EXCLUDED."approved_date", "version" = EXCLUDED."version", "status" = EXCLUDED."status", "policy_id" = EXCLUDED."policy_id", "updated_date" = EXCLUDED."updated_date", "created_by_id" = EXCLUDED."created_by_id", "created_by" = EXCLUDED."created_by", "is_sample" = EXCLUDED."is_sample";
